'use strict';

// PharmaOS WF4 — Domain Brief Prompt Builder v5.0.0
// Model: openai/gpt-4.1-mini

const d = $input.first().json;
const a = d.analytics;
const safe  = (v, fb = 'N/A') => (v == null ? fb : String(v).trim() || fb);
const trunc = (s, mx) => String(s).length > mx ? String(s).slice(0, mx) + '…' : String(s);

const DOMAIN_CONFIG = {
  ci:         { label: 'Competitive Intelligence', audience: 'CI Analysts, Medical Affairs Directors, BD Scouts', icon: '🔍' },
  safety:     { label: 'Drug Safety & PV',          audience: 'Pharmacovigilance Officers, Drug Safety Directors, CMO', icon: '🛡️' },
  regulatory: { label: 'Regulatory Affairs',        audience: 'Regulatory Directors, Submission Managers, Compliance Officers', icon: '📋' },
  bd:         { label: 'Business Development',      audience: 'VP BD, Licensing Directors, M&A Analysts', icon: '💼' }
};

const briefs = [];
for (const [domain, cfg] of Object.entries(DOMAIN_CONFIG)) {
  const ds = a.domains[domain];
  if (!ds || ds.total === 0) continue;

  const dt = a.trends.domainTrends[domain] || { arrow: '→', delta: 0, pctChange: null };

  const signalBlock = ds.topSignals.slice(0, 7).map((s, i) =>
    `${i+1}. [${s.impactlevel}|${s.scoreTier}] ${s.drug} / ${s.indication} / ${s.sponsor}\n` +
    `   Type:${s.signaltype} Score:${s.impactscore}/10 Confidence:${s.confidence} ${s.competitor ? '⚔️COMP' : ''} ${s.urgent ? '🚨URG' : ''}\n` +
    `   Action:${s.action}\n` +
    `   Summary: ${trunc(s.summary, 180)}`
  ).join('\n');

  const compoundImpact = a.compounds.events
    .filter(c => {
      const doms = Array.isArray(c.domains) ? c.domains : (c.domains ? JSON.parse(c.domains) : []);
      return doms.includes(domain);
    })
    .map(c => `⚠️ ${safe(c.triggerpattern)} Risk:${safe(c.compoundriskscore)}/10`)
    .join(', ');

  const sysPrompt = `You are PharmaOS ${cfg.label} Analyst. Write a precise domain intelligence brief for: ${cfg.audience}.

RETURN EXACTLY this JSON structure (no other text):
{
  "domainSummary": string (3-4 sentences, domain-expert language, most critical finding first),
  "topActionItems": [
    { "action": string, "priority": "P0"|"P1"|"P2", "owner": string, "deadline": string }
  ] (max 4 items, P0 = immediate <24h),
  "watchList": string[] (max 4 items to monitor next 72h),
  "riskFlag": string (1 sentence domain-specific risk, or "No elevated domain risk"),
  "opportunityFlag": string (1 sentence domain-specific opportunity, or "No clear opportunity identified")
}

Zero filler. Domain expertise only. Use industry-standard terminology.`;

  const userPrompt = trunc(
    `${cfg.icon} ${domain.toUpperCase()} DOMAIN BRIEF — ${d.today} — ${d.runId}\n\n` +
    `METRICS: ${ds.total} signals | HIGH:${ds.high}(${ds.highPct}%) MED:${ds.med} LOW:${ds.low}\n` +
    `Tier-1:${ds.tier1} | Competitor:${ds.competitor} | Urgent:${ds.urgent}\n` +
    `Avg Score:${ds.avgScore}/10 | Peak:${ds.peakScore}/10 | Quality:${ds.avgQuality}\n` +
    `Trend: ${dt.arrow} ${dt.delta > 0 ? '+' : ''}${dt.delta} vs yesterday ${dt.pctChange != null ? '(' + dt.pctChange + '%)' : ''}\n` +
    (compoundImpact ? `Compound Events affecting domain: ${compoundImpact}\n` : '') +
    `\nTOP SIGNALS:\n${signalBlock || 'No signals in window.'}`, 4500
  );

  briefs.push({ domain, cfg, sysPrompt, userPrompt });
}

return {
  json: {
    ...d,
    domainBriefs: briefs,
    domainAIConfig: {
      model: 'openai/gpt-4.1-mini',
      temperature: 0.18,
      top_p: 0.9,
      max_tokens: 900,
      response_format: { type: 'json_object' },
      seed: 42
    }
  }
};

'use strict';

/**
 * PharmaOS WF4 — Parse Executive AI Response
 * Version: 6.0.0 (Hardened Production Parser)
 */

const item = $input.first()?.json || {};
const rawResp = item?.choices?.[0]?.message?.content ?? '';
const usage = item?.usage ?? {};

let parsed = {};
let parseError = null;

/* ------------------------------------------------
   Utility — Extract JSON from messy LLM output
------------------------------------------------ */

function extractJSON(text) {

  if (!text || typeof text !== 'string') return '{}';

  // remove markdown fences
  let clean = text
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .trim();

  // attempt direct parse first
  try {
    JSON.parse(clean);
    return clean;
  } catch {}

  // attempt bracket extraction
  const start = clean.indexOf('{');
  const end = clean.lastIndexOf('}');

  if (start !== -1 && end !== -1) {
    return clean.slice(start, end + 1);
  }

  return '{}';
}

/* ------------------------------------------------
   Parse AI Output
------------------------------------------------ */

try {

  const jsonStr = extractJSON(rawResp);

  parsed = JSON.parse(jsonStr);

} catch (err) {

  parseError = err?.message || 'Unknown parse error';

  parsed = {
    executiveSummary:
      rawResp?.slice(0, 600) ||
      'AI narrative unavailable — fallback intelligence activated.',

    riskAssessment:
      'Risk intelligence unavailable.',

    topThreat: {
      title: 'Data unavailable',
      domain: 'unknown',
      rationale: '',
      recommendedAction: 'Manual review required',
      owner: 'Ops Team',
      deadline: 'Immediate',
      escalationPath: 'CMO'
    },

    topOpportunity: {
      title: 'Data unavailable',
      domain: 'unknown',
      rationale: '',
      recommendedAction: 'Manual review required',
      owner: 'BD Team',
      deadline: 'This week',
      valueDriver: 'Unknown'
    },

    crossDomainInsight:
      'Cross-domain analysis unavailable.',

    weekAheadOutlook:
      'Forecast unavailable.',

    blindSpotAlert:
      'Blind spot detection unavailable.',

    contradictedDecisions:
      'Unable to assess.',

    sentimentScore: 5,

    _parseError: true
  };
}

/* ------------------------------------------------
   Safe Upstream Node Access
------------------------------------------------ */

let upstream = {};

try {

  const node = $('Build Executive AI Prompt');

  if (node?.first) {
    upstream = node.first()?.json ?? {};
  }

} catch (err) {

  upstream = {
    _nodeReferenceError: true,
    _nodeErrorMessage: err?.message || 'Upstream node unavailable'
  };
}

/* ------------------------------------------------
   Normalize Output Schema
------------------------------------------------ */

const normalized = {

  executiveSummary:
    parsed?.executiveSummary ?? 'Executive summary unavailable.',

  riskAssessment:
    parsed?.riskAssessment ?? 'Risk assessment unavailable.',

  topThreat:
    parsed?.topThreat ?? {},

  topOpportunity:
    parsed?.topOpportunity ?? {},

  crossDomainInsight:
    parsed?.crossDomainInsight ?? '',

  weekAheadOutlook:
    parsed?.weekAheadOutlook ?? '',

  blindSpotAlert:
    parsed?.blindSpotAlert ?? '',

  contradictedDecisions:
    parsed?.contradictedDecisions ?? '',

  sentimentScore:
    typeof parsed?.sentimentScore === 'number'
      ? parsed.sentimentScore
      : 5
};

/* ------------------------------------------------
   Token Accounting
------------------------------------------------ */

const tokenStats = {
  prompt: usage?.prompt_tokens ?? 0,
  completion: usage?.completion_tokens ?? 0,
  total: usage?.total_tokens ?? 0
};

/* ------------------------------------------------
   Model Detection
------------------------------------------------ */

const model =
  upstream?.execAI?.model ||
  item?.model ||
  'openai/gpt-4.1';

/* ------------------------------------------------
   Final Payload
------------------------------------------------ */

return {
  json: {

    ...upstream,

    execNarrative: normalized,

    execTokens: tokenStats,

    execModel: model,

    execParseOk: !parsed?._parseError,

    diagnostics: {

      parseError,

      rawLength: rawResp?.length || 0,

      hasUsage: !!usage,

      timestamp: new Date().toISOString()

    }
  }
};

'use strict';

// ╔══════════════════════════════════════════════════════════════════════════════╗
// ║  PHARMAOS · SLACK DOMAIN ROUTER · n8n Code Node · v2.0.0                  ║
// ║                                                                              ║
// ║  Runs AFTER slack_block_builder_v6.js                                       ║
// ║  Splits domainMessages into one n8n item per domain so the downstream       ║
// ║  Slack Send Message node fires once per channel.                            ║
// ║                                                                              ║
// ║  Fixes from v1:                                                              ║
// ║    • Read domainPayloads — field is now domainMessages (v6 builder)         ║
// ║    • analytics.domains[domain]?.total crash if analytics missing            ║
// ║    • No routing for executive digest — now emits as dedicated item          ║
// ║    • No skip reason logged — now includes reason + audit on skipped items   ║
// ║    • All items share full upstream JSON — large payload per item            ║
// ║      → now strips raw CSV/HTML blobs to keep item size lean                ║
// ║                                                                              ║
// ║  Output items (one per routable payload):                                   ║
// ║    item.json.slackPayload      → { channel, text, blocks } ready to POST   ║
// ║    item.json.currentDomain     → domain key or 'executive'                  ║
// ║    item.json.currentDomainLabel → human label                               ║
// ║    item.json.routeType         → 'domain' | 'executive' | 'skip'           ║
// ╚══════════════════════════════════════════════════════════════════════════════╝

// ═══════════════════════════════════════════════════════════════════════════════
// §0  HELPERS
// ═══════════════════════════════════════════════════════════════════════════════

const safeStr  = (v, fb = '')  => { if (v == null) return fb; const s = String(v).replace(/[\u0000-\u001F]/g,'').trim(); return s || fb; };
const safeNum  = (v, fb = 0)  => { const n = Number(v); return Number.isFinite(n) ? n : fb; };
const safeBool = (v)           => v === true || v === 'true' || v === 1;
const safeObj  = (v)           => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};
const safeArr  = (v)           => Array.isArray(v) ? v : [];
const isoNow   = ()            => new Date().toISOString();

/**
 * Strip large blob fields from upstream JSON before attaching to each item.
 * Keeps item payloads lean — avoids sending 50KB of HTML/CSV in every Slack item.
 * All stripped fields are still accessible in the binary output of the CSV node.
 */
const STRIP_FIELDS = [
  'htmlEmail', 'digest_html', 'digest_text',
  'csvExport', 'csvDomainSummary', 'csvActionItems', 'csvWatchList',
  'csvCompetitorRadar', 'csvIndicationHeatmap', 'csvCompoundEvents',
  'csvStrategyMemory', 'csvTokenUsage', 'csvExecutiveBrief',
  'ai_system_prompt', 'ai_user_prompt', 'ai_input_context',
  'execAI_system_prompt', 'execAI_user_prompt',
  'pagerdutyPayload',   // has its own node
];

const stripBlobs = (obj) => {
  const out = { ...obj };
  for (const k of STRIP_FIELDS) delete out[k];
  return out;
};

// ═══════════════════════════════════════════════════════════════════════════════
// §1  LOAD INPUT
// ═══════════════════════════════════════════════════════════════════════════════

const allItems = $input.all();
if (!allItems || allItems.length === 0) {
  throw new Error('[PharmaOS:SlackRouter] No input items — check upstream Slack builder node');
}

// Use first item as primary data source (router always gets single merged item)
const d    = safeObj(allItems[0].json);
const lean = stripBlobs(d);  // used as base for all output items

// ── Source payloads ───────────────────────────────────────────────────────────
// v6 builder outputs domainMessages (map) + slackExecutiveDigest (object)
// v5 builder output domainPayloads — support both field names
const domainMessages      = safeObj(d.domainMessages || d.domainPayloads || {});
const slackExecutiveDigest = safeObj(d.slackExecutiveDigest || {});

// ── Analytics (for signal-count routing guard) ────────────────────────────────
const aDomains   = safeObj(safeObj(d.analytics).domains);
const aGlobal    = safeObj(safeObj(d.analytics).global);
const aRisk      = safeObj(safeObj(d.analytics).risk);
const aFlags     = safeObj(safeObj(safeObj(d.analytics).analytics).flags);

const today      = safeStr(d.today || new Date().toISOString().slice(0, 10));
const runId      = safeStr(d.runId || safeObj(d._meta).run_id, '—');
const riskLevel  = safeStr(aRisk.level, 'UNKNOWN').toUpperCase();
const riskScore  = safeNum(aRisk.score, 0);
const hasSafetyEsc = safeBool(aFlags.hasSafetyEscalation);
const needsAction  = safeBool(aFlags.requiresImmediateAction);

// ═══════════════════════════════════════════════════════════════════════════════
// §2  ROUTE DOMAIN PAYLOADS
// ═══════════════════════════════════════════════════════════════════════════════

const outputItems  = [];
const routeLog     = [];  // audit: what was routed, what was skipped and why

for (const [domain, payload] of Object.entries(domainMessages)) {
  const p = safeObj(payload);

  // ── Routing guards ────────────────────────────────────────────────────────
  // Guard 1: payload must have blocks or at least a channel
  if (!p.channel && !safeArr(p.blocks).length) {
    routeLog.push({ domain, routed: false, reason: 'payload has no channel or blocks' });
    continue;
  }

  // Guard 2: signal count — skip if domain had zero signals
  // Check payload's own signal_total first, then fall back to analytics
  const signalTotal = safeNum(
    p.signal_total ??
    safeObj(aDomains[domain]).total
  , 0);

  if (signalTotal === 0 && !safeBool(p.needs_escalation)) {
    routeLog.push({ domain, routed: false, reason: `zero signals and no escalation flag`, signal_total: 0 });
    continue;
  }

  // Guard 3: blocks array must be non-empty
  const blocks = safeArr(p.blocks);
  if (blocks.length === 0) {
    routeLog.push({ domain, routed: false, reason: 'blocks array is empty' });
    continue;
  }

  // ── Build Slack-ready payload ─────────────────────────────────────────────
  const slackPayload = {
    channel:  safeStr(p.channel, '#pharmaos-ops'),
    text:     safeStr(p.text, `PharmaOS ${safeStr(p.label || domain).toUpperCase()} Brief — ${today}`),
    blocks:   blocks.slice(0, 50),  // Slack API hard limit
  };

  outputItems.push({
    json: {
      ...lean,

      // Routing context
      currentDomain:      domain,
      currentDomainLabel: safeStr(p.label || domain),
      routeType:          'domain',
      routeIndex:         outputItems.length,

      // The Slack payload — downstream Send Message node reads this
      slackPayload,

      // Quick-access signal stats for downstream IF nodes
      signalTotal,
      highSignals:    safeNum(p.high_signals,   safeObj(aDomains[domain]).high),
      urgentSignals:  safeNum(p.urgent_signals, safeObj(aDomains[domain]).urgent),
      needsEscalation: safeBool(p.needs_escalation),
      blockCount:     blocks.length,

      // Route audit
      _route_meta: {
        domain,
        channel:    slackPayload.channel,
        route_type: 'domain',
        signal_total: signalTotal,
        block_count:  blocks.length,
        routed_at:    isoNow(),
        run_id:       runId,
      },
    },
  });

  routeLog.push({
    domain,
    routed:       true,
    channel:      slackPayload.channel,
    block_count:  blocks.length,
    signal_total: signalTotal,
  });
}

// ═══════════════════════════════════════════════════════════════════════════════
// §3  ROUTE EXECUTIVE DIGEST
// ═══════════════════════════════════════════════════════════════════════════════

// Always emit executive digest if it has blocks — independent of domain signal counts
const execBlocks = safeArr(slackExecutiveDigest.blocks);

if (execBlocks.length > 0 && slackExecutiveDigest.channel) {
  const execPayload = {
    channel: safeStr(slackExecutiveDigest.channel, '#pharmaos-leadership'),
    text:    safeStr(slackExecutiveDigest.text, `PharmaOS Executive Digest — ${today}`),
    blocks:  execBlocks.slice(0, 50),
  };

  outputItems.push({
    json: {
      ...lean,

      currentDomain:      'executive',
      currentDomainLabel: 'Executive Digest',
      routeType:          'executive',
      routeIndex:         outputItems.length,

      slackPayload: execPayload,

      // Exec-level stats for downstream IF nodes
      signalTotal:      safeNum(aGlobal.totalSignals),
      highSignals:      safeNum(aGlobal.highCount),
      urgentSignals:    safeNum(aGlobal.urgentCount),
      hasSafetyEsc,
      needsAction,
      riskLevel,
      riskScore,
      blockCount:       execBlocks.length,
      needsEscalation:  hasSafetyEsc || safeBool(slackExecutiveDigest.needs_action),

      _route_meta: {
        domain:       'executive',
        channel:      execPayload.channel,
        route_type:   'executive',
        block_count:  execBlocks.length,
        signal_total: safeNum(aGlobal.totalSignals),
        routed_at:    isoNow(),
        run_id:       runId,
      },
    },
  });

  routeLog.push({
    domain:      'executive',
    routed:      true,
    channel:     execPayload.channel,
    block_count: execBlocks.length,
  });

} else {
  routeLog.push({
    domain:  'executive',
    routed:  false,
    reason:  execBlocks.length === 0
      ? 'executive digest has no blocks'
      : 'executive digest missing channel',
  });
}

// ═══════════════════════════════════════════════════════════════════════════════
// §4  FALLBACK — nothing routed
// ═══════════════════════════════════════════════════════════════════════════════

if (outputItems.length === 0) {
  const skipReason = Object.keys(domainMessages).length === 0 && !slackExecutiveDigest.channel
    ? 'No domainMessages and no executive digest found — check upstream Slack builder node'
    : `All ${routeLog.length} payloads skipped — see domainDispatchSkipped.reasons`;

  return [{
    json: {
      ...lean,
      currentDomain:       null,
      routeType:           'skip',
      domainDispatchSkipped: true,
      skipReason,
      _route_meta: {
        route_type:    'skip',
        total_payloads_checked: routeLog.length,
        routed:        0,
        skipped:       routeLog.length,
        reasons:       routeLog.map(r => `${r.domain}: ${r.reason || 'routed OK'}`),
        routed_at:     isoNow(),
        run_id:        runId,
      },
    },
  }];
}

// ═══════════════════════════════════════════════════════════════════════════════
// §5  ATTACH DISPATCH SUMMARY TO ALL ITEMS
// ═══════════════════════════════════════════════════════════════════════════════

// Attach a lightweight summary to every item so downstream nodes know
// how many total items were dispatched in this batch
const dispatchSummary = {
  total_routed:   outputItems.length,
  domain_items:   outputItems.filter(i => i.json.routeType === 'domain').length,
  exec_items:     outputItems.filter(i => i.json.routeType === 'executive').length,
  total_skipped:  routeLog.filter(r => !r.routed).length,
  route_log:      routeLog,
  dispatched_at:  isoNow(),
  run_id:         runId,
};

for (const item of outputItems) {
  item.json.dispatchSummary = dispatchSummary;
}

return outputItems;

