'use strict';

// PharmaOS WF4 — Digest Health Check + SLA Validation v5.0.0

const d = $input.first().json;
const now = Date.now();
const startedAt = new Date(d.isoNow).getTime();
const totalLatencyMs = now - startedAt;
const slaTargetMs = new Date(d.sla?.dispatchTarget).getTime() - new Date(d.isoNow).getTime();
const slaBreached = totalLatencyMs > slaTargetMs;

const checks = {
  execAiParseOk:       !!d.execParseOk,
  domainBriefingsOk:   Object.keys(d.domainBriefings || {}).length > 0,
  slackExecPayloadOk:  !!(d.slackExecPayload?.blocks?.length > 0),
  emailPayloadOk:      !!(d.emailPayload?.html?.length > 100),
  auditLogWritten:     true, // If we got here, it was written
  slaBreach:           slaBreached,
  totalLatencyMs
};

const failures = Object.entries(checks)
  .filter(([k, v]) => k !== 'totalLatencyMs' && k !== 'slaBreach' && !v)
  .map(([k]) => k);

const status = failures.length === 0 ? (slaBreached ? 'SLA_BREACH' : 'SUCCESS') : 'PARTIAL_FAILURE';

const healthSummary = {
  runId:         d.runId,
  status,
  checks,
  failures,
  totalLatencyMs,
  slaBreached,
  pipelineVersion: d.pipelineVersion,
  completedAt: new Date().toISOString()
};

// Log to console for n8n execution log
console.log(`[PharmaOS WF4] Run ${d.runId} completed: ${status} in ${totalLatencyMs}ms`);
if (failures.length > 0) console.error(`[PharmaOS WF4] Failures: ${failures.join(', ')}`);
if (slaBreached) console.warn(`[PharmaOS WF4] SLA BREACHED: ${totalLatencyMs}ms > ${slaTargetMs}ms`);

return { json: { ...d, healthSummary } };

'use strict';
// PharmaOS WF4 — Multi-Domain Analytics Engine v5.0.0
const PIPELINE = '5.0.0';
const DOMAINS = ['ci','safety','regulatory','bd'];
const DOMAIN_LABELS = { ci:'Competitive Intelligence', safety:'Drug Safety & PV', regulatory:'Regulatory Affairs', bd:'Business Development' };
const RISK_THRESHOLDS = { CRITICAL: 80, ELEVATED: 50, MODERATE: 30 };

const safe = (v, fb='') => (v==null ? fb : String(v).trim() || fb);
const numOr = (v, fb=0) => { const n=Number(v); return Number.isFinite(n)?n:fb; };
const round2 = n => Math.round(n*100)/100;
const pct = (n,d) => d>0 ? round2((n/d)*100) : 0;

const ctx       = $('Build Context1').first().json;
const stats     = $('Fetch Signals by Domain').all().map(i=>i.json);
const signals   = $('Fetch Top Signals Detail1').all().map(i=>i.json);
const trends    = $('Fetch Trend Data1').all().map(i=>i.json);
const compounds = $('Fetch Active Compound Events1').all().map(i=>i.json);
const compRadar = $('Fetch Competitor Radar1').all().map(i=>i.json);
const portfolio = $('Fetch Asset Portfolio Health1').all().map(i=>i.json);
const strategy  = $('Fetch Strategy Memory1').all().map(i=>i.json);
const health    = $('Fetch Pipeline Health1').all().map(i=>i.json);

// ── 1. GLOBAL METRICS ─────────────────────────────────────────
const totalSignals   = signals.length;
const highSignals    = signals.filter(s=>s.impact_level==='HIGH');
const medSignals     = signals.filter(s=>s.impact_level==='MED');
const lowSignals     = signals.filter(s=>s.impact_level==='LOW');
const criticalTier   = signals.filter(s=>['CRITICAL','SAFETY_ESCALATION'].includes(s.route_tier));
const competitorHits = signals.filter(s=>s.competitor_flag);
const urgentSignals  = signals.filter(s=>s.is_urgent);
const newSignals     = signals.filter(s=>s.signal_status==='NEW');
const updatedSignals = signals.filter(s=>s.signal_status==='UPDATE');
const avgImpact  = totalSignals>0 ? round2(signals.reduce((s,x)=>s+numOr(x.impact_score),0)/totalSignals) : 0;
const peakImpact = totalSignals>0 ? Math.max(...signals.map(s=>numOr(s.impact_score))) : 0;
const avgPriority = totalSignals>0 ? round2(signals.reduce((s,x)=>s+numOr(x.priority_score),0)/totalSignals) : 0;
const confDist = { high:signals.filter(s=>s.confidence==='high').length, medium:signals.filter(s=>s.confidence==='medium').length, low:signals.filter(s=>s.confidence==='low').length };
const overrides = signals.filter(s=>s.override_status&&s.override_status!=='');
const overrideViolations = signals.filter(s=>(s.override_status==='UPGRADE'&&['LOW','DISMISS'].includes(s.route_tier))||(s.override_status==='DOWNGRADE'&&['CRITICAL','SAFETY_ESCALATION'].includes(s.route_tier)));

// ── 2. PER-DOMAIN BREAKDOWN ───────────────────────────────────
const domainAnalytics = {};
for (const d of DOMAINS) {
  const dSigs = signals.filter(s=>s.signal_domain===d);
  const dHigh = dSigs.filter(s=>s.impact_level==='HIGH');
  const dMed  = dSigs.filter(s=>s.impact_level==='MED');
  const dComp = dSigs.filter(s=>s.competitor_flag);
  const dUrg  = dSigs.filter(s=>s.is_urgent);
  const dNew  = dSigs.filter(s=>s.signal_status==='NEW');
  const dCrit = dSigs.filter(s=>['CRITICAL','SAFETY_ESCALATION'].includes(s.route_tier));
  domainAnalytics[d] = {
    label: DOMAIN_LABELS[d], total:dSigs.length, high:dHigh.length, med:dMed.length,
    low:dSigs.length-dHigh.length-dMed.length, competitor:dComp.length, urgent:dUrg.length,
    new:dNew.length, updated:dSigs.length-dNew.length, criticalTier:dCrit.length,
    avgScore: dSigs.length>0 ? round2(dSigs.reduce((s,x)=>s+numOr(x.impact_score),0)/dSigs.length):0,
    peakScore: dSigs.length>0 ? Math.max(...dSigs.map(s=>numOr(s.impact_score))):0,
    highPct: pct(dHigh.length, dSigs.length),
    topSignals: dHigh.concat(dMed).slice(0,8).map(s=>({
      title:safe(s.title,'Untitled'), drug:safe(s.drug_name||s.entity_name,'Unknown'),
      indication:safe(s.indication,'Unknown'), sponsor:safe(s.sponsor,'Unknown'),
      impact_level:s.impact_level, impact_score:numOr(s.impact_score), signal_type:safe(s.signal_type),
      competitor:!!s.competitor_flag, urgent:!!s.is_urgent, action:safe(s.recommended_action,'MONITOR'),
      summary:safe(s.ai_summary,'').slice(0,300), url:safe(s.url), route_tier:safe(s.route_tier),
      confidence:safe(s.confidence), phase:safe(s.phase), nct_id:safe(s.nct_id), domainRank:numOr(s.domain_rank)
    }))
  };
}

// ── 3. TREND ANALYSIS ─────────────────────────────────────────
const todayStr = ctx.today;
const yesterdayStr = new Date(Date.now()-86400000).toISOString().slice(0,10);
const t7dAgo = new Date(Date.now()-7*86400000).toISOString().slice(0,10);
const todayData = trends.filter(t=>t.signal_date===todayStr);
const yesterdayData = trends.filter(t=>t.signal_date===yesterdayStr);
const week7Data = trends.filter(t=>t.signal_date>=t7dAgo);
const todayTotal = todayData.reduce((s,t)=>s+numOr(t.cnt),0);
const yesterdayTotal = yesterdayData.reduce((s,t)=>s+numOr(t.cnt),0);
const weekTotal = week7Data.reduce((s,t)=>s+numOr(t.cnt),0);
const trendDelta = todayTotal-yesterdayTotal;
const trendPct = yesterdayTotal>0 ? round2((trendDelta/yesterdayTotal)*100) : 'N/A';
const trendArrow = trendDelta>0?'📈':trendDelta<0?'📉':'➡️';
const domainTrends = {};
for (const d of DOMAINS) {
  const dT = todayData.filter(t=>t.signal_domain===d).reduce((s,t)=>s+numOr(t.cnt),0);
  const dY = yesterdayData.filter(t=>t.signal_domain===d).reduce((s,t)=>s+numOr(t.cnt),0);
  const dW = week7Data.filter(t=>t.signal_domain===d).reduce((s,t)=>s+numOr(t.cnt),0);
  domainTrends[d] = { today:dT, yesterday:dY, delta:dT-dY, weekTotal:dW, arrow:dT>dY?'↑':dT<dY?'↓':'→', pct:dY>0?round2(((dT-dY)/dY)*100):0 };
}

// ── 4. COMPOUND EVENT ANALYSIS ────────────────────────────────
const activeCompounds = compounds.length;
const executiveEscalations = compounds.filter(c=>c.escalation_level==='EXECUTIVE');
const seniorEscalations = compounds.filter(c=>c.escalation_level==='SENIOR');
const compoundByPattern = {};
for (const c of compounds) { const p=safe(c.trigger_pattern,'UNKNOWN'); compoundByPattern[p]=(compoundByPattern[p]||0)+1; }
const avgCompoundAge = compounds.length>0 ? round2(compounds.reduce((s,c)=>s+numOr(c.age_minutes),0)/compounds.length) : 0;

// ── 5. INDICATION HEATMAP ─────────────────────────────────────
const indicationMap = {};
for (const s of signals) {
  const ind = safe(s.indication,'Unknown');
  if(ind==='Unknown') continue;
  if(!indicationMap[ind]) indicationMap[ind]={total:0,high:0,med:0,competitor:0,urgent:0,scores:[],domains:new Set()};
  indicationMap[ind].total++;
  if(s.impact_level==='HIGH') indicationMap[ind].high++;
  if(s.impact_level==='MED') indicationMap[ind].med++;
  if(s.competitor_flag) indicationMap[ind].competitor++;
  if(s.is_urgent) indicationMap[ind].urgent++;
  indicationMap[ind].scores.push(numOr(s.impact_score));
  indicationMap[ind].domains.add(s.signal_domain);
}
const indicationHeatmap = Object.entries(indicationMap).map(([ind,data])=>({
  indication:ind, ...data, domains:[...data.domains],
  avgScore:round2(data.scores.reduce((a,b)=>a+b,0)/data.scores.length)
})).sort((a,b)=>b.high-a.high||b.total-a.total).slice(0,15);

// ── 6. GEOGRAPHIC DENSITY ─────────────────────────────────────
const geoMap = {};
for (const s of signals) {
  const geo = safe(s.geography,'');
  if(!geo) continue;
  if(!geoMap[geo]) geoMap[geo]={total:0,high:0,competitor:0,urgent:0};
  geoMap[geo].total++; if(s.impact_level==='HIGH') geoMap[geo].high++;
  if(s.competitor_flag) geoMap[geo].competitor++; if(s.is_urgent) geoMap[geo].urgent++;
}
const geoHeatmap = Object.entries(geoMap).map(([g,d])=>({geography:g,...d})).sort((a,b)=>b.high-a.high||b.total-a.total).slice(0,10);

// ── 7. SIGNAL VELOCITY ────────────────────────────────────────
const velocityBuckets = {FAST:0,ACTIVE:0,SLOW:0,STABLE:0};
let fastSignals = [];
for (const s of signals) {
  const ageH=numOr(s.age_hours,999), ver=numOr(s.version,1);
  if(ver>1&&ageH>0) {
    const vel=(ver-1)/(ageH+1);
    if(vel>1.0){velocityBuckets.FAST++;fastSignals.push(s);}
    else if(vel>0.25) velocityBuckets.ACTIVE++;
    else if(vel>0.05) velocityBuckets.SLOW++;
    else velocityBuckets.STABLE++;
  } else velocityBuckets.STABLE++;
}

// ── 8. ASSET COVERAGE GAP DETECTION ──────────────────────────
const criticalAssets = portfolio.filter(a=>['CRITICAL','HIGH'].includes(safe(a.strategicpriority)));
const blindSpotAssets = criticalAssets.filter(a=>numOr(a.signals_24h)===0);
const exposedAssets = portfolio.filter(a=>numOr(a.active_compound_events)>0);
const hotAssets = portfolio.filter(a=>numOr(a.high_24h)>=2).sort((a,b)=>numOr(b.high_24h)-numOr(a.high_24h));

// ── 9. COMPOSITE RISK SCORE ───────────────────────────────────
let riskScore=0;
riskScore += Math.min(highSignals.length*1.5, 15);
riskScore += Math.min(criticalTier.length*3, 15);
riskScore += Math.min(urgentSignals.length*2, 10);
riskScore += Math.min(executiveEscalations.length*5, 15);
riskScore += Math.min(activeCompounds*2, 10);
riskScore += Math.min(competitorHits.length*0.5, 10);
riskScore += peakImpact>=9?5:peakImpact>=7?3:0;
riskScore += overrideViolations.length*3;
riskScore += blindSpotAssets.length*2;
riskScore += (domainAnalytics.safety?.high||0)*4;
riskScore += (domainAnalytics.safety?.urgent||0)*3;
riskScore += Math.min(velocityBuckets.FAST*1, 5);
riskScore = Math.min(Math.round(riskScore), 100);
const riskLevel = riskScore>=RISK_THRESHOLDS.CRITICAL?'CRITICAL':riskScore>=RISK_THRESHOLDS.ELEVATED?'ELEVATED':riskScore>=RISK_THRESHOLDS.MODERATE?'MODERATE':'LOW';
const riskEmoji = {CRITICAL:'🔴',ELEVATED:'🟠',MODERATE:'🟡',LOW:'🟢'}[riskLevel];
const riskColor = {CRITICAL:'#DC2626',ELEVATED:'#EA580C',MODERATE:'#CA8A04',LOW:'#16A34A'}[riskLevel];

// ── 10. STRATEGY MEMORY OVERLAY ───────────────────────────────
const recentDecisions = strategy.slice(0,10).map(m=>({
  type:safe(m.decision_type), asset:safe(m.asset_id),
  decision:safe(m.decision_made).slice(0,200), by:safe(m.made_by),
  at:m.made_at?String(m.made_at).slice(0,10):'unknown', ageDays:round2(numOr(m.age_days))
}));

// ── 11. PIPELINE HEALTH ───────────────────────────────────────
const pipelineMetrics = {};
for (const h of health) { pipelineMetrics[safe(h.metricname)]={avg:numOr(h.avg_value),peak:numOr(h.peak_value),min:numOr(h.min_value),p95:numOr(h.p95_value),samples:numOr(h.sample_count)}; }

// ── 12. SIGNAL TYPE DISTRIBUTION ─────────────────────────────
const typeBreakdown = {};
for (const s of signals) { const t=safe(s.signal_type,'other'); typeBreakdown[t]=(typeBreakdown[t]||0)+1; }

// ── 13. SOURCE DISTRIBUTION ───────────────────────────────────
const sourceBreakdown = {};
for (const s of signals) { const src=safe(s.source,'unknown'); sourceBreakdown[src]=(sourceBreakdown[src]||0)+1; }

// ── 14. TOP DRUGS BY ACTIVITY ─────────────────────────────────
const drugActivity = {};
for (const s of signals) {
  const drug=safe(s.drug_name||s.entity_name,'');
  if(!drug) continue;
  if(!drugActivity[drug]) drugActivity[drug]={count:0,peakScore:0,domains:new Set(),high:0,urgent:0};
  drugActivity[drug].count++; drugActivity[drug].peakScore=Math.max(drugActivity[drug].peakScore,numOr(s.impact_score));
  drugActivity[drug].domains.add(s.signal_domain);
  if(s.impact_level==='HIGH') drugActivity[drug].high++;
  if(s.is_urgent) drugActivity[drug].urgent++;
}
const topDrugs = Object.entries(drugActivity).map(([name,d])=>({name,count:d.count,peakScore:d.peakScore,domains:[...d.domains],high:d.high,urgent:d.urgent})).sort((a,b)=>b.peakScore-a.peakScore||b.count-a.count).slice(0,10);

// ── SAFETY ESCALATION FLAG ────────────────────────────────────
const hasSafetyEscalation = (domainAnalytics.safety?.criticalTier||0)>0 || urgentSignals.some(s=>s.signal_domain==='safety');
const requiresImmediateAction = executiveEscalations.length>0 || hasSafetyEscalation || riskScore>=RISK_THRESHOLDS.CRITICAL;

return {
  json: {
    ...ctx,
    analytics: {
      global: {
        totalSignals, highCount:highSignals.length, medCount:medSignals.length,
        lowCount:lowSignals.length, criticalTierCount:criticalTier.length,
        competitorCount:competitorHits.length, urgentCount:urgentSignals.length,
        newCount:newSignals.length, updatedCount:updatedSignals.length,
        avgImpact, peakImpact, avgPriority, confDist,
        overrideCount:overrides.length, overrideViolations:overrideViolations.length,
        weekTotal
      },
      domains: domainAnalytics,
      trends: { todayTotal,yesterdayTotal,trendDelta,trendPct,trendArrow,domainTrends,weekTotal },
      compounds: { active:activeCompounds, executiveEscalations:executiveEscalations.length, seniorEscalations:seniorEscalations.length, byPattern:compoundByPattern, avgAgeMins:avgCompoundAge, events:compounds.slice(0,10) },
      competitorRadar: compRadar.slice(0,15),
      indicationHeatmap, geoHeatmap,
      velocity: { ...velocityBuckets, fastSignals: fastSignals.slice(0,5).map(s=>({title:safe(s.title),drug:safe(s.drug_name||s.entity_name),domain:s.signal_domain})) },
      portfolio: {
        totalAssets:portfolio.length, criticalAssets:criticalAssets.length,
        blindSpots: blindSpotAssets.map(a=>({id:a.asset_id,name:a.asset_name,priority:a.strategicpriority})),
        exposed: exposedAssets.map(a=>({id:a.asset_id,name:a.asset_name,compounds:a.active_compound_events,risk:a.compound_peak_risk,execEscalations:a.exec_escalation_count})),
        hotAssets: hotAssets.slice(0,5).map(a=>({id:a.asset_id,name:a.asset_name,high24h:a.high_24h,competitor24h:a.competitor_24h}))
      },
      risk: { score:riskScore, level:riskLevel, emoji:riskEmoji, color:riskColor },
      strategyMemory: recentDecisions,
      pipelineHealth: pipelineMetrics,
      typeBreakdown, sourceBreakdown, topDrugs,
      flags: { hasSafetyEscalation, requiresImmediateAction }
    },
    topSignals: signals.slice(0,30),
    compoundEvents: compounds.slice(0,10)
  }
};

'use strict';
// PharmaOS WF4 — Aggregate Domain Brief Responses v5.0.0
const allItems = $input.all();
const domainBriefings = {};
let domainTokensTotal = 0;

for (const item of allItems) {
  const d = item.json;
  const domainBriefs = d.domainBriefs || [];
  const runIdx = d.$runIndex || 0;
  const brief = domainBriefs[runIdx] || {};
  const domain = brief.domain || 'unknown';
  const raw = d.choices?.[0]?.message?.content || '{}';
  domainTokensTotal += d.usage?.total_tokens || 0;
  let parsed = {};
  try {
    const clean = raw.replace(/```json|^```|```$/gm,'').trim();
    parsed = JSON.parse(clean);
  } catch(e) {
    parsed = {
      domainSummary: `${domain.toUpperCase()} domain AI parse error — review raw signals.`,
      riskLevel: 'HIGH', topActionItems: [{ action:'Manual review required', priority:'P0', owner:'Domain Lead', deadline:'Immediate' }],
      watchList: ['AI unavailable — check raw signals'], keyInsight: 'AI parse error.', escalationNeeded: true, _parseError: true
    };
  }
  domainBriefings[domain] = { ...parsed, _domain: domain, _audience: brief.audience || '' };
}

// Pass through last item's full context merged with all domain briefings
const ctx = allItems[allItems.length-1]?.json || {};
return {
  json: {
    ...ctx,
    domainBriefings,
    domainTokensTotal
  }
};

