const safeStr  = (v, fb = 'N/A') => { if (v == null) return fb; const s = String(v).replace(/[\u0000-\u001F]/g,'').trim(); return s || fb; };
const safeNum  = (v, fb = 0)     => { const n = Number(v); return Number.isFinite(n) ? n : fb; };
const safeBool = (v)              => v === true || v === 'true' || v === 1;
const safeObj  = (v)              => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};
const safeArr  = (v)              => Array.isArray(v) ? v : [];
const isoNow   = ()               => new Date().toISOString();

/** Truncate to Slack text limit */
const slk = (v, max = 3000) => {
  const s = safeStr(v, '');
  return s.length > max ? s.slice(0, max - 1) + '…' : s;
};

/** Risk progress bar  ████░░░░░░ 62/100 */
const riskBar = (score) => {
  const n      = safeNum(score, 0);
  const filled = Math.min(10, Math.round(n / 10));
  return '`' + '█'.repeat(filled) + '░'.repeat(10 - filled) + ` ${n}/100` + '`';
};

/** Trend arrow with colour context */
const trendLabel = (delta, pct, arrow) => {
  const d = safeNum(delta);
  const p = safeNum(pct);
  const a = safeStr(arrow, '→');
  return `${a} ${d > 0 ? '+' : ''}${d} (${p > 0 ? '+' : ''}${p}%)`;
};

/** Section mrkdwn block */
const txt = (text) => ({ type: 'section', text: { type: 'mrkdwn', text: slk(text) } });

/** Header block */
const hdr = (text) => ({
  type: 'header',
  text: { type: 'plain_text', text: slk(text, 150), emoji: true },
});

/** Context footer */
const ctx = (...parts) => ({
  type: 'context',
  elements: [{ type: 'mrkdwn', text: slk(parts.filter(Boolean).join(' | '), 2000) }],
});

/** Divider */
const DIV = { type: 'divider' };

/** Section with field pairs — max 10 per Slack spec */
const fieldBlock = (pairs) => ({
  type: 'section',
  fields: pairs.slice(0, 10).map(([label, val]) => ({
    type: 'mrkdwn',
    text: `*${slk(label, 80)}*\n${slk(safeStr(val, '—'), 300)}`,
  })),
});

/** Add with 50-block hard cap */
const add = (arr, ...blocks) => {
  for (const b of blocks) {
    if (!b) continue;
    if (arr.length >= 49) {
      arr.push(ctx('⚠️ Additional blocks truncated — see full digest in dashboard'));
      return;
    }
    arr.push(b);
  }
};

// ═══════════════════════════════════════════════════════════════════════════════
// §1  LOAD & VALIDATE INPUT
// ═══════════════════════════════════════════════════════════════════════════════

const allItems = $input.all();
if (!allItems || allItems.length === 0) {
  throw new Error('[PharmaOS:SlackExec] No input items — check upstream node');
}

const d = safeObj(allItems[0].json);

// ── Analytics ─────────────────────────────────────────────────────────────────
const a          = safeObj(d.analytics);
const aGlobal    = safeObj(a.global);
const aRisk      = safeObj(a.risk);
const aTrends    = safeObj(a.trends);
const aDomains   = safeObj(a.domains);
const aCompounds = safeObj(a.compounds);
const aPortfolio = safeObj(a.portfolio);
// FIX: flags live at a.analytics.flags not a.flags
const aFlags     = safeObj(safeObj(a.analytics).flags);
const aDomTrends = safeObj(aTrends.domainTrends);

// ── Executive AI output ───────────────────────────────────────────────────────
// FIX: field is execAI_result / execAIResult — not execNarrative
const exec = safeObj(
  d.execAI_result   ||
  d.execAIResult    ||
  d.execAI_parsed   ||
  d.execNarrative   ||   // keep v5 compat
  d.executiveBrief  ||
  {}
);

// ── Meta ──────────────────────────────────────────────────────────────────────
const today       = safeStr(d.today       || new Date().toISOString().slice(0, 10));
const runId       = safeStr(d.runId       || safeObj(d._meta).run_id,              '—');
const triggerType = safeStr(d.triggerType || safeObj(d._meta).trigger_type,        'SCHEDULED').toUpperCase();
const pipeVer     = safeStr(d.pipelineversion || safeObj(d._meta).pipeline_version,'—');
const window_     = safeStr(safeObj(d.windows).primary,                            '72h');
const totalTokens = safeNum(d.totalTokensUsed || safeObj(d._meta).estimated_tokens);
const dashUrl     = safeStr(d.dashboardUrl || 'https://pharmaos.internal/dashboard');

// ── Risk fields ───────────────────────────────────────────────────────────────
const riskLevel   = safeStr(aRisk.level, 'UNKNOWN').toUpperCase();
const riskScore   = safeNum(aRisk.score, 0);
const riskEmoji   = safeStr(aRisk.emoji,
  riskLevel === 'CRITICAL' ? '🔴' :
  riskLevel === 'HIGH'     ? '🟠' :
  riskLevel === 'MODERATE' ? '🟡' :
  riskLevel === 'LOW'      ? '🟢' : '⚪'
);
const riskTrend   = safeStr(aRisk.trend, '');

// ── Global metrics ────────────────────────────────────────────────────────────
const highCount       = safeNum(aGlobal.highCount);
const medCount        = safeNum(aGlobal.medCount);
const lowCount        = safeNum(aGlobal.lowCount);
const totalSignals    = safeNum(aGlobal.totalSignals);
const criticalTier    = safeNum(aGlobal.criticalTierCount);
const competitorCount = safeNum(aGlobal.competitorCount);
const urgentCount     = safeNum(aGlobal.urgentCount);
const newCount        = safeNum(aGlobal.newCount);
const updatedCount    = safeNum(aGlobal.updatedCount);
const peakImpact      = safeNum(aGlobal.peakImpact, 0).toFixed(1);
const avgImpact       = safeNum(aGlobal.avgImpact,  0).toFixed(1);
const overrideViol    = safeNum(aGlobal.overrideViolations);
const aiCovPct        = safeNum(aGlobal.aiCoveragePct);

// ── Flags ─────────────────────────────────────────────────────────────────────
const requiresAction  = safeBool(aFlags.requiresImmediateAction);
const hasSafetyEsc    = safeBool(aFlags.hasSafetyEscalation);
const execEscalations = safeNum(aCompounds.executiveEscalations);
const compoundActive  = safeNum(aCompounds.active);

// ── Exec AI fields ────────────────────────────────────────────────────────────
const execSummary     = safeStr(exec.executiveSummary  || exec.executive_summary,  '');
const riskAssessment  = safeStr(exec.riskAssessment    || exec.risk_assessment,    '');
const safetyAlert     = safeStr(exec.safetyAlert       || exec.safety_alert,       '');
const crossDomain     = safeStr(exec.crossDomainInsight|| exec.cross_domain_insight,'');
const competitorThr   = safeStr(exec.competitorThreat  || exec.competitor_threat,  '');
const weekAhead       = safeStr(exec.weekAheadOutlook  || exec.week_ahead_outlook, '');
const blindSpot       = safeStr(exec.blindSpotAlert    || exec.blind_spot_alert,   '');
const velocityOut     = safeStr(exec.velocityOutlook   || exec.velocity_outlook,   '');
const confidenceNote  = safeStr(exec.confidenceNote    || exec.confidence_note,    '');
const topThreat       = safeObj(exec.topThreat);
const topOpp          = safeObj(exec.topOpportunity);

// ── Guard: no analytics → graceful fallback ───────────────────────────────────
if (!aRisk.level && !execSummary) {
  return [{
    json: {
      ...d,
      slackExecBlocks: [{
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: '*PharmaOS Intelligence Digest*\n⚠️ Analytics payload missing — check upstream Compute Analytics / Merge AI nodes.\n_Run ID: ' + runId + ' | ' + today + '_',
        },
      }],
      slackExecChannelId: '#pharmaos-executive',
      slackExecFallback: true,
    },
  }];
}

// ═══════════════════════════════════════════════════════════════════════════════
// §2  BUILD BLOCKS
// ═══════════════════════════════════════════════════════════════════════════════

const blocks = [];

// ── HEADER ────────────────────────────────────────────────────────────────────
add(blocks,
  hdr(`${riskEmoji} PharmaOS Intelligence Digest — ${today}`)
);

// ── CRITICAL BANNERS ─────────────────────────────────────────────────────────
if (hasSafetyEsc) {
  add(blocks, txt(':rotating_light: *SAFETY ESCALATION ACTIVE* — CMO notification required immediately.'));
}
if (requiresAction || riskLevel === 'CRITICAL') {
  add(blocks, txt(
    `:rotating_light: *IMMEDIATE ACTION REQUIRED* — ` +
    `${execEscalations > 0 ? `${execEscalations} executive escalation(s) active. ` : ''}` +
    `Risk: ${riskEmoji} ${riskLevel} (${riskScore}/100)`
  ));
}
if (overrideViol > 0) {
  add(blocks, txt(`⚠️ *${overrideViol} Override Violation(s)* — Compliance review required.`));
}
if (hasSafetyEsc || requiresAction || overrideViol > 0) {
  add(blocks, DIV);
}

// ── RISK STATUS BAR ───────────────────────────────────────────────────────────
add(blocks, {
  type: 'section',
  text: {
    type: 'mrkdwn',
    text: slk(
      `*Risk Status:* ${riskEmoji} *${riskLevel}* ${riskTrend ? `_(${riskTrend})_` : ''}\n` +
      `${riskBar(riskScore)}\n` +
      `*Trigger:* ${triggerType} | *Run ID:* \`${runId}\` | *Window:* ${window_}`
    ),
  },
  accessory: {
    type: 'button',
    text: { type: 'plain_text', text: 'View Dashboard ↗', emoji: true },
    url: dashUrl,
    action_id: 'open_dashboard',
  },
});
add(blocks, DIV);

// ── GLOBAL METRICS ────────────────────────────────────────────────────────────
add(blocks, txt(`*Signal Overview — ${window_} window (${totalSignals} total)*`));
add(blocks, fieldBlock([
  ['🔴 HIGH',        `${highCount} signals`],
  ['🟡 MED',         `${medCount} signals`],
  ['💀 Critical Tier',`${criticalTier} signals`],
  ['⚔️ Competitor',  `${competitorCount} signals`],
  ['🚨 Urgent',      `${urgentCount} signals`],
  ['📈 Trend',       trendLabel(aTrends.trendDelta, aTrends.trendPct, aTrends.trendArrow)],
  ['🆕 New/Updated', `${newCount} new | ${updatedCount} updated`],
  ['📊 Peak/Avg',    `${peakImpact}/10 peak | ${avgImpact} avg`],
]));
add(blocks, DIV);

// ── COMPOUND EVENTS ───────────────────────────────────────────────────────────
if (compoundActive > 0) {
  add(blocks, txt(
    `*⚠️ Active Compound Events (${compoundActive})` +
    (execEscalations > 0 ? ` — ${execEscalations} Exec Escalation(s)` : '') + '*'
  ));

  // FIX: a.compounds.events may be undefined — use safeArr
  const compEvents = safeArr(aCompounds.events || aCompounds.compoundEvents);
  for (const c of compEvents.slice(0, 3)) {
    if (!c) continue;
    const ageMin = safeNum(c.age_minutes);
    const age    = ageMin < 60  ? `${Math.round(ageMin)}min`
                 : ageMin < 1440 ? `${(ageMin/60).toFixed(1)}h`
                 : `${(ageMin/1440).toFixed(1)}d`;
    add(blocks, txt(
      `> *${slk(c.title || c.trigger_pattern, 100)}*\n` +
      `> Pattern: ${safeStr(c.trigger_pattern)} | Risk: *${safeStr(c.compound_risk_score)}/10* | ` +
      `Escalation: *${safeStr(c.escalation_level)}* | Age: ${age} | ` +
      `Signals: ${safeNum(c.affected_signal_count)}`
    ));
  }
  add(blocks, DIV);
}

// ── EXECUTIVE SUMMARY ─────────────────────────────────────────────────────────
if (execSummary) {
  add(blocks, txt(`*🧠 Executive Summary*\n${execSummary}`));
}
if (riskAssessment) {
  add(blocks, txt(`*📊 Risk Assessment*\n${riskAssessment}`));
}
if (execSummary || riskAssessment) {
  add(blocks, DIV);
}

// ── SAFETY ALERT ──────────────────────────────────────────────────────────────
if (safetyAlert) {
  add(blocks,
    txt(`*🩺 Safety Alert — CMO Notification Required*\n:warning: ${safetyAlert}`),
    DIV
  );
}

// ── TOP THREAT ────────────────────────────────────────────────────────────────
if (topThreat.title) {
  add(blocks, txt([
    `*🎯 Top Threat: ${slk(topThreat.title, 100)}*`,
    `> *Domain:* ${safeStr(topThreat.domain, '—').toUpperCase()} | *Severity:* ${safeStr(topThreat.severity, '—')} | *Asset:* ${safeStr(topThreat.affectedAsset, '—')}`,
    topThreat.rationale         ? `> _${slk(topThreat.rationale, 300)}_`              : null,
    topThreat.recommendedAction ? `> *Action:* ${slk(topThreat.recommendedAction, 200)}` : null,
    (topThreat.owner || topThreat.deadline) ?
      `> *Owner:* ${safeStr(topThreat.owner, '—')} | *Deadline:* \`${safeStr(topThreat.deadline, '—')}\`` : null,
  ].filter(Boolean).join('\n')));
}

// ── TOP OPPORTUNITY ───────────────────────────────────────────────────────────
if (topOpp.title) {
  add(blocks, txt([
    `*💡 Top Opportunity: ${slk(topOpp.title, 100)}*`,
    `> *Domain:* ${safeStr(topOpp.domain, '—').toUpperCase()} | *Value:* ${safeStr(topOpp.value, '—')} | *Asset:* ${safeStr(topOpp.affectedAsset, '—')}`,
    topOpp.rationale         ? `> _${slk(topOpp.rationale, 300)}_`              : null,
    topOpp.recommendedAction ? `> *Action:* ${slk(topOpp.recommendedAction, 200)}` : null,
    (topOpp.owner || topOpp.deadline) ?
      `> *Owner:* ${safeStr(topOpp.owner, '—')} | *Deadline:* \`${safeStr(topOpp.deadline, '—')}\`` : null,
  ].filter(Boolean).join('\n')));
}

if (topThreat.title || topOpp.title) {
  add(blocks, DIV);
}

// ── CROSS-DOMAIN CONVERGENCE ──────────────────────────────────────────────────
if (crossDomain) {
  add(blocks, txt(`*🔗 Cross-Domain Signal Convergence*\n${crossDomain}`));
}

// ── COMPETITOR THREAT ─────────────────────────────────────────────────────────
if (competitorThr) {
  add(blocks, txt(`*⚔️ Competitor Threat*\n${competitorThr}`));
}

// ── WEEK AHEAD ────────────────────────────────────────────────────────────────
if (weekAhead) {
  add(blocks, txt(`*🔭 Week Ahead Outlook*\n${weekAhead}`));
}

// ── VELOCITY ──────────────────────────────────────────────────────────────────
if (velocityOut) {
  add(blocks, txt(`*📡 Signal Velocity*\n${velocityOut}`));
}

// ── BLIND SPOTS ───────────────────────────────────────────────────────────────
if (blindSpot) {
  add(blocks, txt(`*🔍 Coverage Gap*\n:warning: ${blindSpot}`));
}

if (crossDomain || competitorThr || weekAhead || blindSpot || velocityOut) {
  add(blocks, DIV);
}

// ── CONFIDENCE NOTE ───────────────────────────────────────────────────────────
if (confidenceNote) {
  add(blocks, txt(`_ℹ️ ${confidenceNote}_`));
}

// ── DOMAIN SUMMARY GRID ───────────────────────────────────────────────────────
const domainEntries = Object.entries(aDomains);
if (domainEntries.length > 0) {
  add(blocks, txt('*Domain Coverage:*'));
  // FIX: Slack section fields max is 10 — chunk if needed
  const domPairs = domainEntries.map(([dom, v]) => {
    if (!v) return null;
    const dt    = safeObj(aDomTrends[dom]);
    const arrow = safeStr(dt.arrow, '→');
    const pct   = safeNum(dt.pct, 0);
    const high  = safeNum(v.high);
    return [
      dom.toUpperCase(),
      `${safeNum(v.total)} total | H:${high > 0 ? `🔴${high}` : high} | ${arrow}${pct > 0 ? '+' : ''}${pct}%`,
    ];
  }).filter(Boolean);

  // Chunk into groups of 10 (Slack fields max)
  for (let i = 0; i < domPairs.length; i += 10) {
    add(blocks, fieldBlock(domPairs.slice(i, i + 10)));
  }
  add(blocks, DIV);
}

// ── PORTFOLIO BLIND SPOTS ─────────────────────────────────────────────────────
const blindSpotAssets = safeArr(aPortfolio.blindSpots).slice(0, 4);
if (blindSpotAssets.length > 0) {
  const lines = blindSpotAssets.map(b =>
    `• *${safeStr(b?.name, '—')}* (${safeStr(b?.priority, '—')}) — zero signal coverage`
  );
  add(blocks, txt(`*⚠️ Asset Blind Spots (${blindSpotAssets.length}):*\n${lines.join('\n')}`));
  add(blocks, DIV);
}

// ── ACTION BUTTONS ────────────────────────────────────────────────────────────
add(blocks, {
  type: 'actions',
  elements: [
    {
      type: 'button',
      text: { type: 'plain_text', text: '📧 Full Email Report', emoji: true },
      style: 'primary',
      action_id: 'email_report',
      value: 'send_email',
    },
    {
      type: 'button',
      text: { type: 'plain_text', text: '⚠️ Escalate to CMO', emoji: true },
      style: 'danger',
      action_id: 'escalate_cmo',
      value: 'escalate_cmo',
    },
    {
      type: 'overflow',
      action_id: 'exec_overflow',
      options: [
        { text: { type: 'plain_text', text: '📊 View Full Report'   }, value: 'view_report'   },
        { text: { type: 'plain_text', text: '✅ Acknowledge'         }, value: 'acknowledge'   },
        { text: { type: 'plain_text', text: '📥 Download CSV'        }, value: 'download_csv'  },
        { text: { type: 'plain_text', text: '🚨 PagerDuty Alert'     }, value: 'pagerduty'     },
        { text: { type: 'plain_text', text: '🔕 Snooze 4h'           }, value: 'snooze_4h'     },
      ],
    },
  ],
});

// ── CONTEXT FOOTER ────────────────────────────────────────────────────────────
add(blocks, ctx(
  `PharmaOS v${pipeVer}`,
  `Run: ${runId}`,
  triggerType,
  totalTokens > 0 ? `${totalTokens.toLocaleString()} tokens` : null,
  aiCovPct > 0    ? `AI coverage: ${aiCovPct}%`              : null,
  isoNow(),
));

// ═══════════════════════════════════════════════════════════════════════════════
// §3  NOTIFICATION TEXT (Slack mobile fallback)
// ═══════════════════════════════════════════════════════════════════════════════

const notificationText = [
  `PharmaOS Digest - ${today}`,
  `${riskEmoji} ${riskLevel} (${riskScore}/100)`,
  `${totalSignals} signals | ${highCount} HIGH | ${urgentCount} Urgent`,
  hasSafetyEsc     ? 'SAFETY ESCALATION ACTIVE' : null,
  execEscalations > 0 ? `${execEscalations} exec escalation(s)` : null,
].filter(Boolean).join(' | ');

// ═══════════════════════════════════════════════════════════════════════════════
// §4  AUDIT META
// ═══════════════════════════════════════════════════════════════════════════════

const _slack_exec_meta = {
  node:          'slack_exec_block_builder',
  version:       'v6.0.0',
  built_at:      isoNow(),
  run_id:        runId,
  today,
  block_count:   Math.min(blocks.length, 50),
  risk_level:    riskLevel,
  risk_score:    riskScore,
  has_exec_ai:   !!(execSummary || topThreat.title),
  has_safety:    !!safetyAlert,
  has_compounds: compoundActive > 0,
  compound_count: compoundActive,
  exec_escalations: execEscalations,
  domain_count:  domainEntries.length,
  total_signals: totalSignals,
};

// ═══════════════════════════════════════════════════════════════════════════════
// §5  RETURN  — FIX: must be array
// ═══════════════════════════════════════════════════════════════════════════════

return [{
  json: {
    ...d,
    slackExecBlocks:     blocks.slice(0, 50),
    slackExecChannelId:  '#pharmaos-executive',
    notificationText,
    _slack_exec_meta,
  },
}];

'use strict';

// ╔══════════════════════════════════════════════════════════════════════════════╗
// ║  PHARMAOS · DOMAIN SLACK BLOCK BUILDER · n8n Code Node · v6.0.0           ║
// ║                                                                              ║
// ║  Fixes from v5.0.0:                                                          ║
// ║    • `blocks` referenced in return outside loop scope → ReferenceError      ║
// ║    • Input reads $input.first() but data is array → reads all items         ║
// ║    • Return shape missing domainMessages → downstream Slack nodes got {}    ║
// ║    • domain key "unknown" not in DOMAIN_CHANNELS → silently dropped         ║
// ║    • No null-guard on ds.total → crash if analytics missing                 ║
// ║    • action_id uses Math.random → not stable, breaks Slack dedup            ║
// ║    • Slack section fields array max is 10 — no guard                        ║
// ║    • Text fields not truncated to Slack's 3000-char limit                   ║
// ║                                                                              ║
// ║  Enhancements:                                                               ║
// ║    • One Slack message payload per domain in domainMessages                 ║
// ║    • Global executive digest payload in slackExecutiveDigest                ║
// ║    • Risk/opportunity flag banners                                           ║
// ║    • Competitor radar section                                                ║
// ║    • Stable action_id derived from domain + signal source_id               ║
// ║    • All text fields truncated to Slack API limits                          ║
// ║    • Block count guard (50 max per Slack API)                               ║
// ║    • Full audit _slack_meta on output                                       ║
// ╚══════════════════════════════════════════════════════════════════════════════╝

// ═══════════════════════════════════════════════════════════════════════════════
// §0  HELPERS
// ═══════════════════════════════════════════════════════════════════════════════

const safeStr  = (v, fb = '')  => { if (v == null) return fb; const s = String(v).replace(/[\u0000-\u001F]/g,'').trim(); return s || fb; };
const safeNum  = (v, fb = 0)  => { const n = Number(v); return Number.isFinite(n) ? n : fb; };
const safeBool = (v)           => v === true || v === 'true' || v === 1;
const safeObj  = (v)           => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};
const safeArr  = (v)           => Array.isArray(v) ? v : [];
const isoNow   = ()            => new Date().toISOString();

/**
 * Truncate to Slack's text limits and escape mrkdwn-breaking chars.
 * Slack limits: section text 3000, header 150, context 2000, button label 75
 */
const slk = (v, max = 3000) => {
  const s = safeStr(v);
  return s.length > max ? s.slice(0, max - 1) + '…' : s;
};

/** Stable action_id — no random, deterministic per domain+signal */
const actionId = (domain, sigId, idx) =>
  `pd_${safeStr(domain).slice(0,8)}_${safeStr(sigId || idx).replace(/[^a-zA-Z0-9_-]/g,'').slice(0,20)}_${idx}`.slice(0, 255);

/** Priority badge text */
const prioBadge = (p) => {
  const s = safeStr(p).toUpperCase();
  return s === 'P1' ? '🔴 P1' : s === 'P2' ? '🟠 P2' : s === 'P3' ? '🟡 P3' : `• ${s||'—'}`;
};

/** Impact icon */
const impactIcon = (level) => {
  const l = safeStr(level).toUpperCase();
  return l === 'HIGH' ? '🔴' : l === 'MED' ? '🟡' : l === 'LOW' ? '🟢' : '⚪';
};

/** Risk colour word → emoji */
const riskEmoji = (level) => {
  const l = safeStr(level).toUpperCase();
  return l === 'CRITICAL' ? '🔴' : l === 'HIGH' ? '🟠' : l === 'MODERATE' || l === 'MEDIUM' ? '🟡' : l === 'LOW' ? '🟢' : '⚪';
};

/** Divider block */
const DIV = { type: 'divider' };

/** Section with mrkdwn text */
const txt = (text) => ({ type: 'section', text: { type: 'mrkdwn', text: slk(text) } });

/** Context footer element */
const ctx = (...parts) => ({
  type: 'context',
  elements: [{ type: 'mrkdwn', text: slk(parts.filter(Boolean).join(' | '), 2000) }],
});

/** Header block */
const hdr = (text) => ({
  type: 'header',
  text: { type: 'plain_text', text: slk(text, 150), emoji: true },
});

/** Section with up to 10 fields (Slack API max) */
const fields = (pairs) => ({
  type: 'section',
  fields: pairs.slice(0, 10).map(([label, val]) => ({
    type: 'mrkdwn',
    text: `*${slk(label, 100)}*\n${slk(safeStr(val, '—'), 200)}`,
  })),
});

/** Add blocks with guard — never exceed Slack's 50-block limit */
const addBlocks = (arr, ...newBlocks) => {
  for (const b of newBlocks) {
    if (!b) continue;
    if (arr.length >= 49) {
      arr.push(ctx('⚠️ Additional blocks truncated — see full digest in dashboard'));
      break;
    }
    arr.push(b);
  }
};

// ═══════════════════════════════════════════════════════════════════════════════
// §1  LOAD & AGGREGATE INPUT
// ═══════════════════════════════════════════════════════════════════════════════

// Aggregate across ALL input items (matches html/csv builder pattern)
const allItems = $input.all();
if (!allItems || allItems.length === 0) {
  throw new Error('[PharmaOS:SlackBuilder] No input items — check upstream node');
}

// Merge domain briefings from all items
const allDomainBriefings = {};
let sharedData           = {};

for (const item of allItems) {
  const d = safeObj(item.json);

  // Merge domainBriefings
  const briefings = safeObj(d.domainBriefings);
  for (const [k, v] of Object.entries(briefings)) {
    if (v && typeof v === 'object') allDomainBriefings[k] = v;
  }

  // Keep latest shared fields
  if (Object.keys(d).length > Object.keys(sharedData).length) sharedData = d;
}

const d          = sharedData;
const a          = safeObj(d.analytics);
const aDomains   = safeObj(a.domains);
const aGlobal    = safeObj(a.global);
const aRisk      = safeObj(a.risk);
const aCompounds = safeObj(a.compounds);
const aPortfolio = safeObj(a.portfolio);
const aFlags     = safeObj(safeObj(a.analytics).flags);
const aCompRad   = safeArr(a.competitorRadar);
const execAI     = safeObj(d.execAI_result || d.execAIResult || d.execAI_parsed || {});

const today    = safeStr(d.today || new Date().toISOString().slice(0, 10));
const runId    = safeStr(d.runId || d.run_id, '—');
const pipeVer  = safeStr(d.pipelineversion || safeObj(d._meta).pipeline_version, '—');
const riskLevel = safeStr(aRisk.level || 'UNKNOWN').toUpperCase();
const riskScore = safeNum(aRisk.score, 0);
const domainList = Object.keys(allDomainBriefings);

// ── Config maps ───────────────────────────────────────────────────────────────
const DOMAIN_CHANNELS = {
  ci:         '#pharmaos-ci-team',
  safety:     '#pharmaos-safety',
  regulatory: '#pharmaos-medical-affairs',
  bd:         '#pharmaos-bd-team',
  unknown:    '#pharmaos-intelligence',
  general:    '#pharmaos-intelligence',
};

const DOMAIN_EMOJI = {
  ci:         '🔬',
  safety:     '🛡️',
  regulatory: '📋',
  bd:         '🤝',
  unknown:    '🧬',
  general:    '🧬',
};

const DOMAIN_LABEL = {
  ci:         'Competitive Intelligence',
  safety:     'Safety',
  regulatory: 'Regulatory',
  bd:         'Business Development',
  unknown:    'Intelligence',
  general:    'General Intelligence',
};

// ═══════════════════════════════════════════════════════════════════════════════
// §2  PER-DOMAIN MESSAGE BUILDER
// ═══════════════════════════════════════════════════════════════════════════════

const domainMessages = {};

for (const [domain, briefing] of Object.entries(allDomainBriefings)) {
  const b      = safeObj(briefing);
  const ds     = safeObj(aDomains[domain]);
  const emoji  = DOMAIN_EMOJI[domain]  || '📊';
  const label  = DOMAIN_LABEL[domain]  || domain.toUpperCase();
  const chan   = DOMAIN_CHANNELS[domain] || '#pharmaos-ops';

  const total      = safeNum(ds.total,      0);
  const high       = safeNum(ds.high,       0);
  const med        = safeNum(ds.med,        0);
  const low        = safeNum(ds.low,        0);
  const competitor = safeNum(ds.competitor, 0);
  const urgent     = safeNum(ds.urgent,     0);
  const avgScore   = safeNum(ds.avgScore,   0).toFixed(1);
  const peakScore  = safeNum(ds.peakScore,  0).toFixed(1);

  const domRisk     = safeStr(b.riskLevel || b.riskFlag, 'No elevated risk');
  const domOpp      = safeStr(b.opportunityFlag, '');
  const summary     = safeStr(b.domainSummary, '');
  const keyInsight  = safeStr(b.keyInsight, '');
  const actions     = safeArr(b.topActionItems);
  const watchList   = safeArr(b.watchList);
  const topSigs     = safeArr(ds.topSignals);
  const needsEsc    = safeBool(b.escalationNeeded);

  const blocks = [];

  // ── HEADER ───────────────────────────────────────────────────────────────
  addBlocks(blocks,
    hdr(`${emoji} ${label} Brief — ${today}`)
  );

  // ── ESCALATION BANNER (top, if needed) ───────────────────────────────────
  if (needsEsc) {
    addBlocks(blocks,
      txt(':rotating_light: *ESCALATION REQUIRED* — Domain lead must review immediately.')
    );
  }

  // ── RISK / OPPORTUNITY FLAGS ──────────────────────────────────────────────
  if (domRisk && !domRisk.toLowerCase().includes('no elevated')) {
    addBlocks(blocks,
      txt(`⚠️ *Risk Flag:* ${slk(domRisk, 400)}`)
    );
  }
  if (domOpp) {
    addBlocks(blocks,
      txt(`💡 *Opportunity:* ${slk(domOpp, 400)}`)
    );
  }

  // ── METRICS ROW ──────────────────────────────────────────────────────────
  // Slack section fields: max 10, render in 2-column grid
  const metricPairs = [
    ['Total Signals', total],
    ['HIGH',          high > 0 ? `🔴 ${high}` : high],
    ['MED',           med],
    ['Competitor',    competitor > 0 ? `⚔️ ${competitor}` : competitor],
    ['Urgent',        urgent > 0 ? `🚨 ${urgent}` : urgent],
    ['Avg / Peak',    `${avgScore} / ${peakScore}`],
  ];
  addBlocks(blocks, fields(metricPairs));
  addBlocks(blocks, DIV);

  // ── KEY INSIGHT ───────────────────────────────────────────────────────────
  if (keyInsight) {
    addBlocks(blocks,
      txt(`*💡 Key Insight*\n${keyInsight}`)
    );
  }

  // ── DOMAIN SUMMARY ────────────────────────────────────────────────────────
  if (summary) {
    addBlocks(blocks,
      txt(`*Summary*\n${summary}`)
    );
  }

  if (keyInsight || summary) {
    addBlocks(blocks, DIV);
  }

  // ── ACTION ITEMS ──────────────────────────────────────────────────────────
  if (actions.length > 0) {
    const lines = actions.slice(0, 5).map((item, i) => {
      const action   = safeStr(item.action || item.text || item);
      const prio     = prioBadge(item.priority);
      const owner    = safeStr(item.owner, '—');
      const deadline = safeStr(item.deadline, '—');
      return `${i + 1}. ${prio} ${slk(action, 200)} — *${owner}* by \`${deadline}\``;
    });

    addBlocks(blocks,
      txt(`*📋 Action Items (${actions.length} total):*\n${lines.join('\n')}`)
    );
    addBlocks(blocks, DIV);
  }

  // ── TOP SIGNALS ───────────────────────────────────────────────────────────
  if (topSigs.length > 0) {
    addBlocks(blocks,
      txt(`*📡 Top Signals (${Math.min(topSigs.length, 5)} of ${topSigs.length}):*`)
    );

    for (const [idx, s] of topSigs.slice(0, 5).entries()) {
      if (!s) continue;

      const impLvl    = safeStr(s.impact_level  || s.impactlevel,  'MED').toUpperCase();
      const icon      = impactIcon(impLvl);
      const drug      = safeStr(s.drug_name   || s.drug   || s.drugname   || s.entity_name || s.entityname, 'Unknown');
      const indication = safeStr(s.indication, '—');
      const sigType   = safeStr(s.signal_type || s.signaltype, '—');
      const score     = safeNum(s.impact_score  || s.impactscore, 0);
      const compFlag  = safeBool(s.competitor_flag || s.competitor || s.competitorflag);
      const isUrgent  = safeBool(s.is_urgent || s.urgent || s.isurgent);
      const summary   = safeStr(s.ai_summary || s.summary || s.aisummary, '').slice(0, 250);
      const url       = safeStr(s.url, '');
      const sigId     = safeStr(s.source_id || s.signal_id || s.id || idx);
      const sponsor   = safeStr(s.sponsor, '');
      const phase     = safeStr(s.phase, '');

      const badges    = [
        compFlag  ? '⚔️ Competitor' : null,
        isUrgent  ? '🚨 Urgent'     : null,
        sponsor   ? `Sponsor: ${sponsor}` : null,
        phase     ? `Phase ${phase}` : null,
      ].filter(Boolean).join(' · ');

      const textLines = [
        `${icon} *${slk(drug, 80)}* — ${slk(indication, 80)}`,
        `${slk(sigType, 60)} | Score: *${score}/10* | ${impLvl}${badges ? ` | ${badges}` : ''}`,
        summary ? `> ${slk(summary, 250)}` : null,
      ].filter(Boolean).join('\n');

      const sigBlock = {
        type: 'section',
        text: { type: 'mrkdwn', text: slk(textLines) },
      };

      if (url) {
        sigBlock.accessory = {
          type: 'button',
          text: { type: 'plain_text', text: 'Source ↗', emoji: false },
          url: safeStr(url).slice(0, 3000),
          action_id: actionId(domain, sigId, idx),
        };
      }

      addBlocks(blocks, sigBlock);
    }

    addBlocks(blocks, DIV);
  }

  // ── WATCH LIST ────────────────────────────────────────────────────────────
  if (watchList.length > 0) {
    const wlLines = watchList.slice(0, 6).map((w, i) => {
      const text = safeStr(typeof w === 'object' ? (w.item || JSON.stringify(w)) : w);
      return `${i + 1}. ${slk(text, 200)}`;
    });
    addBlocks(blocks,
      txt(`*👁 Watch List (next 48h):*\n${wlLines.join('\n')}`)
    );
  }

  // ── CONTEXT FOOTER ────────────────────────────────────────────────────────
  addBlocks(blocks,
    ctx(
      `PharmaOS ${label}`,
      today,
      `${total} signals`,
      `Run: ${runId}`,
      `v${pipeVer}`
    )
  );

  // Final safety cap
  domainMessages[domain] = {
    channel:          chan,
    text:             `PharmaOS ${label} Brief — ${today} | ${total} signals | ${high > 0 ? `${high} HIGH` : 'No HIGH signals'}`,
    blocks:           blocks.slice(0, 50),
    block_count:      Math.min(blocks.length, 50),
    domain:           domain,
    label:            label,
    signal_total:     total,
    high_signals:     high,
    urgent_signals:   urgent,
    needs_escalation: needsEsc,
  };
}

// ═══════════════════════════════════════════════════════════════════════════════
// §3  GLOBAL EXECUTIVE DIGEST (goes to #pharmaos-leadership or #pharmaos-ops)
// ═══════════════════════════════════════════════════════════════════════════════

const execBlocks = [];

const totalSignals    = safeNum(aGlobal.totalSignals);
const highCount       = safeNum(aGlobal.highCount);
const urgentCount     = safeNum(aGlobal.urgentCount);
const competitorCount = safeNum(aGlobal.competitorCount);
const execEscalations = safeNum(aCompounds.executiveEscalations);
const compoundActive  = safeNum(aCompounds.active);
const overrideViol    = safeNum(aGlobal.overrideViolations);
const hasSafetyEsc    = safeBool(aFlags.hasSafetyEscalation);
const needsAction     = safeBool(aFlags.requiresImmediateAction);

// Executive header
addBlocks(execBlocks,
  hdr(`🧠 PharmaOS Executive Digest — ${today}`)
);

// Critical banners
if (hasSafetyEsc) {
  addBlocks(execBlocks,
    txt(':rotating_light: *SAFETY ESCALATION ACTIVE* — CMO notification required immediately.')
  );
}
if (needsAction) {
  addBlocks(execBlocks,
    txt('⚡ *IMMEDIATE ACTION REQUIRED* — Response needed within 2 hours.')
  );
}
if (execEscalations > 0) {
  addBlocks(execBlocks,
    txt(`🔺 *${execEscalations} Executive Escalation(s)* — Compound event(s) require C-suite attention.`)
  );
}
if (overrideViol > 0) {
  addBlocks(execBlocks,
    txt(`⚠️ *${overrideViol} Override Violation(s)* — Compliance review required.`)
  );
}

// Risk badge + global metrics
addBlocks(execBlocks,
  fields([
    ['Risk Level',   `${riskEmoji(riskLevel)} ${riskLevel} (${riskScore}/100)`],
    ['Total Signals', totalSignals],
    ['HIGH',          highCount > 0 ? `🔴 ${highCount}` : highCount],
    ['Urgent',        urgentCount > 0 ? `🚨 ${urgentCount}` : urgentCount],
    ['Competitor',    competitorCount > 0 ? `⚔️ ${competitorCount}` : competitorCount],
    ['Compounds',     compoundActive > 0 ? `🔺 ${compoundActive}` : compoundActive],
  ])
);

// Executive AI summary
const execSummary = safeStr(execAI.executiveSummary || execAI.executive_summary, '');
if (execSummary) {
  addBlocks(execBlocks, DIV);
  addBlocks(execBlocks,
    txt(`*Executive Summary*\n${execSummary}`)
  );
}

// Top threat + opportunity
const topThreat = safeObj(execAI.topThreat);
const topOpp    = safeObj(execAI.topOpportunity);

if (topThreat.title || topOpp.title) {
  addBlocks(execBlocks, DIV);
}

if (topThreat.title) {
  addBlocks(execBlocks,
    txt([
      `⚠️ *Top Threat: ${slk(topThreat.title, 100)}*`,
      topThreat.domain   ? `Domain: ${topThreat.domain.toUpperCase()}` : null,
      topThreat.severity ? `Severity: ${topThreat.severity}` : null,
      topThreat.affectedAsset ? `Asset: ${topThreat.affectedAsset}` : null,
      topThreat.rationale ? `_${slk(topThreat.rationale, 300)}_` : null,
      topThreat.recommendedAction ? `*Action:* ${slk(topThreat.recommendedAction, 200)} — *${safeStr(topThreat.owner)}* by \`${safeStr(topThreat.deadline)}\`` : null,
    ].filter(Boolean).join('\n'))
  );
}

if (topOpp.title) {
  addBlocks(execBlocks,
    txt([
      `💡 *Top Opportunity: ${slk(topOpp.title, 100)}*`,
      topOpp.domain ? `Domain: ${topOpp.domain.toUpperCase()}` : null,
      topOpp.value  ? `Value: ${topOpp.value}` : null,
      topOpp.rationale ? `_${slk(topOpp.rationale, 300)}_` : null,
      topOpp.recommendedAction ? `*Action:* ${slk(topOpp.recommendedAction, 200)} — *${safeStr(topOpp.owner)}* by \`${safeStr(topOpp.deadline)}\`` : null,
    ].filter(Boolean).join('\n'))
  );
}

// Week ahead
const weekAhead = safeStr(execAI.weekAheadOutlook || execAI.week_ahead_outlook, '');
if (weekAhead) {
  addBlocks(execBlocks, DIV);
  addBlocks(execBlocks,
    txt(`*📅 Week Ahead*\n${weekAhead}`)
  );
}

// Blind spot alert
const blindSpot = safeStr(execAI.blindSpotAlert || execAI.blind_spot_alert, '');
if (blindSpot) {
  addBlocks(execBlocks,
    txt(`*⚠️ Blind Spot Alert*\n${blindSpot}`)
  );
}

// Competitor threat
const compThreat = safeStr(execAI.competitorThreat || execAI.competitor_threat, '');
if (compThreat) {
  addBlocks(execBlocks,
    txt(`*⚔️ Competitor Threat*\n${compThreat}`)
  );
}

// Domain coverage summary
if (domainList.length > 0) {
  addBlocks(execBlocks, DIV);
  const domainLines = domainList.map(dom => {
    const ds = safeObj(aDomains[dom]);
    const b  = safeObj(allDomainBriefings[dom]);
    return `• *${DOMAIN_LABEL[dom] || dom.toUpperCase()}:* ${safeNum(ds.total)} signals | HIGH: ${safeNum(ds.high)} | ${safeStr(b.riskFlag || 'No elevated risk')}`;
  });
  addBlocks(execBlocks,
    txt(`*Domain Coverage (${domainList.length}):*\n${domainLines.join('\n')}`)
  );
}

// Executive context footer
addBlocks(execBlocks,
  ctx(
    'PharmaOS Executive Digest',
    today,
    `${totalSignals} signals across ${domainList.length} domain(s)`,
    `Run: ${runId}`,
    `v${pipeVer}`
  )
);

const slackExecutiveDigest = {
  channel:          '#pharmaos-leadership',
  text:             `PharmaOS Digest — ${today} | ${riskEmoji(riskLevel)} ${riskLevel} (${riskScore}/100) | ${totalSignals} signals | ${highCount} HIGH | ${urgentCount} Urgent`,
  blocks:           execBlocks.slice(0, 50),
  block_count:      Math.min(execBlocks.length, 50),
  risk_level:       riskLevel,
  risk_score:       riskScore,
  total_signals:    totalSignals,
  high_signals:     highCount,
  urgent_signals:   urgentCount,
  has_safety_esc:   hasSafetyEsc,
  needs_action:     needsAction,
};

// ═══════════════════════════════════════════════════════════════════════════════
// §4  AUDIT META
// ═══════════════════════════════════════════════════════════════════════════════

const _slack_meta = {
  node:               'domain_slack_block_builder',
  version:            'v6.0.0',
  built_at:           isoNow(),
  run_id:             runId,
  today,
  domains_built:      Object.keys(domainMessages),
  domain_count:       Object.keys(domainMessages).length,
  exec_digest_blocks: execBlocks.length,
  total_blocks_built: Object.values(domainMessages).reduce((s, m) => s + m.block_count, 0) + execBlocks.length,
  has_safety_esc:     hasSafetyEsc,
  needs_action:       needsAction,
  exec_escalations:   execEscalations,
};

// ═══════════════════════════════════════════════════════════════════════════════
// §5  RETURN
// ═══════════════════════════════════════════════════════════════════════════════

return [{
  json: {
    ...d,

    // Per-domain Slack payloads — one entry per domain
    // Each has: { channel, text, blocks, block_count, domain, label, signal_total }
    domainMessages,

    // Global executive digest — send to #pharmaos-leadership
    slackExecutiveDigest,

    // Backward-compat: single-domain shortcut for simple workflows
    // Points to first available domain, or executive digest if no domains
    slackDomainDispatch: domainList.length > 0
      ? domainMessages[domainList[0]]
      : slackExecutiveDigest,

    // Notification text for Slack fallback (shown in mobile notifications)
    notificationText: `PharmaOS Digest — ${today} | ${riskEmoji(riskLevel)} ${riskLevel} | ${totalSignals} signals | ${highCount} HIGH`,

    _slack_meta,
  },
}];

'use strict';

// ╔══════════════════════════════════════════════════════════════════════════════╗
// ║  PHARMAOS · HTML EMAIL BUILDER · n8n Code Node · v3.1.0                   ║
// ║                                                                              ║
// ║  Input shape (from OpenRouter response array):                               ║
// ║    $input.all() → array of items, each item is an OpenRouter chat response  ║
// ║    item.json.domainBriefings.{domain} → domain intelligence object          ║
// ║    item.json.choices[0].message.content → raw JSON string (already parsed   ║
// ║      into domainBriefings by upstream node)                                  ║
// ║    item.json.usage → token usage                                             ║
// ╚══════════════════════════════════════════════════════════════════════════════╝

// ═══════════════════════════════════════════════════════════════════════════════
// §0  HELPERS
// ═══════════════════════════════════════════════════════════════════════════════

const safeStr  = (v, fb = '')  => { if (v == null) return fb; const s = String(v).replace(/[\u0000-\u001F]/g, '').trim(); return s || fb; };
const safeNum  = (v, fb = 0)  => { const n = Number(v); return Number.isFinite(n) ? n : fb; };
const safeObj  = (v)           => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};
const safeArr  = (v)           => Array.isArray(v) ? v : [];
const esc      = (v)           => safeStr(v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
const trunc    = (s, mx)       => { const t = safeStr(s); return t.length > mx ? t.slice(0, mx) + '…' : t; };
const isoNow   = ()            => new Date().toISOString();
const fmtDate  = (s)           => { try { return new Date(s || Date.now()).toLocaleDateString('en-US',{weekday:'short',year:'numeric',month:'short',day:'2-digit'}); } catch(_) { return safeStr(s); } };

/** Parse JSON string safely — returns {} or [] depending on expected type */
const parseJ = (v, fallback = {}) => {
  if (!v) return fallback;
  if (typeof v === 'object') return v;
  try { return JSON.parse(v); } catch (_) { return fallback; }
};

// ═══════════════════════════════════════════════════════════════════════════════
// §1  LOAD & AGGREGATE ALL INPUT ITEMS
// ═══════════════════════════════════════════════════════════════════════════════

const allItems = $input.all();
if (!allItems || allItems.length === 0) {
  throw new Error('[PharmaOS:HtmlEmail] No input items — check upstream node');
}

// Aggregate domain briefings across all items (one item per domain call)
const allDomainBriefings = {};   // { domainKey: briefingObj }
let   totalTokens        = 0;
let   totalCost          = 0;
let   modelUsed          = '';
let   runId              = '';
let   today              = fmtDate(new Date().toISOString());

// Also try to find analytics/meta from any item that has it
let sharedAnalytics = {};
let sharedMeta      = {};
let execAIResult    = {};

for (const item of allItems) {
  const d = safeObj(item.json);

  // Aggregate domain briefings — handle domainBriefings object
  const briefings = safeObj(d.domainBriefings);
  for (const [domainKey, briefObj] of Object.entries(briefings)) {
    if (briefObj && typeof briefObj === 'object') {
      allDomainBriefings[domainKey] = briefObj;
    }
  }

  // Also try choices[0].message.content if domainBriefings not pre-parsed
  const choices = safeArr(d.choices);
  if (choices.length > 0 && !Object.keys(briefings).length) {
    const content = safeStr(choices[0]?.message?.content);
    if (content) {
      const parsed = parseJ(content, {});
      // Treat as a single briefing under the model/domain key
      const domainKey = safeStr(d.domainBriefings?.unknown?._domain || 'general');
      allDomainBriefings[domainKey] = { ...parsed, _domain: domainKey };
    }
  }

  // Token aggregation
  const usage = safeObj(d.usage);
  totalTokens += safeNum(usage.total_tokens);
  totalCost   += safeNum(usage.cost);

  // Model
  if (!modelUsed) modelUsed = safeStr(d.model);

  // Shared context from upstream nodes
  if (d.analytics)  sharedAnalytics = safeObj(d.analytics);
  if (d._meta)      sharedMeta      = safeObj(d._meta);
  if (d.today)      today           = safeStr(d.today);
  if (d.runId)      runId           = safeStr(d.runId);

  // Executive AI brief
  if (d.execAI_result || d.execAIResult) {
    execAIResult = safeObj(d.execAI_result || d.execAIResult);
  }
}

// ── Flatten analytics ─────────────────────────────────────────────────────────
const aGlobal    = safeObj(sharedAnalytics.global);
const aRisk      = safeObj(sharedAnalytics.risk);
const aCompounds = safeObj(sharedAnalytics.compounds);
const aPortfolio = safeObj(sharedAnalytics.portfolio);
const aDomains   = safeObj(sharedAnalytics.domains);
const aFlags     = safeObj(safeObj(sharedAnalytics.analytics).flags);

// Key metrics (with fallback to 0 if analytics not available)
const totalSignals    = safeNum(aGlobal.totalSignals);
const highCount       = safeNum(aGlobal.highCount);
const medCount        = safeNum(aGlobal.medCount);
const urgentCount     = safeNum(aGlobal.urgentCount);
const competitorCount = safeNum(aGlobal.competitorCount);
const criticalTier    = safeNum(aGlobal.criticalTierCount);
const compoundActive  = safeNum(aCompounds.active);
const execEscalations = safeNum(aCompounds.executiveEscalations);
const overrideViol    = safeNum(aGlobal.overrideViolations);
const avgImpact       = safeNum(aGlobal.avgImpact, 0).toFixed(1);
const peakImpact      = safeNum(aGlobal.peakImpact, 0).toFixed(1);
const hasSafetyEsc    = aFlags.hasSafetyEscalation === true;
const needsAction     = aFlags.requiresImmediateAction === true;

const riskLevel  = safeStr(aRisk.level, 'MODERATE').toUpperCase();
const riskScore  = safeNum(aRisk.score, 50);
const riskEmoji  = riskLevel === 'CRITICAL' ? '🔴' : riskLevel === 'HIGH' ? '🟠' : riskLevel === 'MODERATE' ? '🟡' : riskLevel === 'LOW' ? '🟢' : '⚪';
const riskColour = riskLevel === 'CRITICAL' ? '#DC2626' : riskLevel === 'HIGH' ? '#EA580C' : riskLevel === 'MODERATE' ? '#CA8A04' : riskLevel === 'LOW' ? '#16A34A' : '#6B7280';

const domainCount   = Object.keys(allDomainBriefings).length;
const pipeVer       = safeStr(sharedMeta.pipeline_version, '—');
const builtAt       = safeStr(sharedMeta.built_at || isoNow());

// ── Executive AI fields ───────────────────────────────────────────────────────
const execSummary     = safeStr(execAIResult.executiveSummary   || execAIResult.executive_summary);
const execRisk        = safeStr(execAIResult.riskAssessment     || execAIResult.risk_assessment);
const weekAhead       = safeStr(execAIResult.weekAheadOutlook   || execAIResult.week_ahead_outlook);
const crossDomain     = safeStr(execAIResult.crossDomainInsight || execAIResult.cross_domain_insight);
const safetyAlert     = safeStr(execAIResult.safetyAlert        || execAIResult.safety_alert);
const blindSpotAlert  = safeStr(execAIResult.blindSpotAlert     || execAIResult.blind_spot_alert);
const competitorThreat = safeStr(execAIResult.competitorThreat  || execAIResult.competitor_threat);
const topThreat       = safeObj(execAIResult.topThreat);
const topOpportunity  = safeObj(execAIResult.topOpportunity);

// ═══════════════════════════════════════════════════════════════════════════════
// §2  HTML COMPONENT BUILDERS
// ═══════════════════════════════════════════════════════════════════════════════

// ── §2A  Alert banners ────────────────────────────────────────────────────────
const buildBanners = () => {
  const b = [];
  if (hasSafetyEsc) b.push(`
    <div style="background:#FEF2F2;border-left:4px solid #DC2626;padding:12px 16px;margin-bottom:10px;border-radius:0 6px 6px 0;">
      <strong style="color:#DC2626;">🚨 SAFETY ESCALATION ACTIVE</strong>
      <span style="color:#7F1D1D;margin-left:8px;font-size:13px;">CMO notification required immediately.</span>
    </div>`);
  if (needsAction) b.push(`
    <div style="background:#FFF7ED;border-left:4px solid #EA580C;padding:12px 16px;margin-bottom:10px;border-radius:0 6px 6px 0;">
      <strong style="color:#EA580C;">⚡ IMMEDIATE ACTION REQUIRED</strong>
      <span style="color:#7C2D12;margin-left:8px;font-size:13px;">Response required within 2 hours.</span>
    </div>`);
  if (execEscalations > 0) b.push(`
    <div style="background:#F5F3FF;border-left:4px solid #7C3AED;padding:12px 16px;margin-bottom:10px;border-radius:0 6px 6px 0;">
