      <span style="color:#78350F;margin-left:8px;font-size:13px;">${overrideViol} override violation(s) detected — review required.</span>
    </div>`);
  return b.length > 0 ? `<div style="margin-bottom:20px;">${b.join('')}</div>` : '';
};

// ── §2B  Executive summary block ──────────────────────────────────────────────
const buildExecSummary = () => {
  if (!execSummary && !execRisk) return '';
  return `
  <div style="background:#F0F9FF;border:1px solid #BAE6FD;border-radius:8px;padding:20px;margin-bottom:24px;">
