    </h3>
    ${execSummary ? `<p style="color:#1E3A5F;line-height:1.7;margin:0 0 12px;font-size:14px;">${esc(execSummary)}</p>` : ''}
    ${execRisk    ? `<p style="color:#475569;line-height:1.6;margin:0;font-size:13px;font-style:italic;border-top:1px solid #BAE6FD;padding-top:10px;">${esc(execRisk)}</p>` : ''}
    ${crossDomain ? `<div style="margin-top:12px;padding:10px;background:#E0F2FE;border-radius:4px;font-size:13px;color:#075985;">
      <strong>Cross-Domain Convergence:</strong> ${esc(crossDomain)}
