  </div>`;
};

// ── §2C  Threat & Opportunity cards ──────────────────────────────────────────
const buildThreatOpportunity = () => {
  if (!topThreat.title && !topOpportunity.title) return '';
  const threatCard = topThreat.title ? `
    <div style="flex:1;background:#FEF2F2;border:1px solid #FECACA;border-radius:8px;padding:16px;">
      <div style="font-size:11px;font-weight:700;letter-spacing:1px;color:#991B1B;margin-bottom:8px;">⚠️ TOP THREAT</div>
      <div style="font-weight:700;color:#1F2937;margin-bottom:6px;font-size:14px;">${esc(topThreat.title)}</div>
      <div style="font-size:12px;color:#6B7280;margin-bottom:8px;">
        ${topThreat.domain ? `<span style="background:#FEE2E2;color:#991B1B;padding:2px 8px;border-radius:10px;margin-right:6px;">${esc(topThreat.domain).toUpperCase()}</span>` : ''}
        ${topThreat.severity ? `<span style="background:#FEE2E2;color:#991B1B;padding:2px 8px;border-radius:10px;">${esc(topThreat.severity)}</span>` : ''}
      </div>
      ${topThreat.rationale ? `<p style="font-size:13px;color:#374151;line-height:1.5;margin:0 0 8px;">${esc(topThreat.rationale)}</p>` : ''}
      ${topThreat.recommendedAction ? `<div style="background:#FFF;border-left:3px solid #DC2626;padding:8px;font-size:12px;color:#374151;margin-top:8px;">
        <strong>Action:</strong> ${esc(topThreat.recommendedAction)}<br>
        ${topThreat.owner ? `<strong>Owner:</strong> ${esc(topThreat.owner)} | ` : ''}
        ${topThreat.deadline ? `<strong>By:</strong> ${esc(topThreat.deadline)}` : ''}
      </div>` : ''}
    </div>` : '<div style="flex:1"></div>';

  const oppCard = topOpportunity.title ? `
    <div style="flex:1;background:#F0FDF4;border:1px solid #BBF7D0;border-radius:8px;padding:16px;">
      <div style="font-size:11px;font-weight:700;letter-spacing:1px;color:#166534;margin-bottom:8px;">💡 TOP OPPORTUNITY</div>
      <div style="font-weight:700;color:#1F2937;margin-bottom:6px;font-size:14px;">${esc(topOpportunity.title)}</div>
      <div style="font-size:12px;color:#6B7280;margin-bottom:8px;">
        ${topOpportunity.domain ? `<span style="background:#DCFCE7;color:#166534;padding:2px 8px;border-radius:10px;margin-right:6px;">${esc(topOpportunity.domain).toUpperCase()}</span>` : ''}
        ${topOpportunity.value  ? `<span style="background:#DCFCE7;color:#166534;padding:2px 8px;border-radius:10px;">${esc(topOpportunity.value)}</span>` : ''}
      </div>
