        <strong>Action:</strong> ${esc(topOpportunity.recommendedAction)}<br>
        ${topOpportunity.owner ? `<strong>Owner:</strong> ${esc(topOpportunity.owner)} | ` : ''}
        ${topOpportunity.deadline ? `<strong>By:</strong> ${esc(topOpportunity.deadline)}` : ''}
      </div>` : ''}
    </div>` : '<div style="flex:1"></div>';

  return `
  <div style="display:flex;gap:16px;margin-bottom:24px;">
    ${threatCard}
    ${oppCard}
  </div>`;
};

// ── §2D  Domain briefings — one card per domain ───────────────────────────────
const buildDomainBriefings = () => {
  const domainEntries = Object.entries(allDomainBriefings);
  if (domainEntries.length === 0) return '';

  const DOMAIN_META = {
    safety:     { label: 'Safety',                color: '#DC2626', bg: '#FEF2F2', border: '#FECACA', emoji: '🛡️' },
    ci:         { label: 'Competitive Intel',      color: '#2563EB', bg: '#EFF6FF', border: '#BFDBFE', emoji: '⚔️' },
    regulatory: { label: 'Regulatory',             color: '#7C3AED', bg: '#F5F3FF', border: '#DDD6FE', emoji: '📋' },
    bd:         { label: 'Business Development',   color: '#059669', bg: '#ECFDF5', border: '#A7F3D0', emoji: '🤝' },
    unknown:    { label: 'Intelligence',           color: '#0891B2', bg: '#F0F9FF', border: '#BAE6FD', emoji: '🔬' },
    general:    { label: 'General Intelligence',  color: '#0891B2', bg: '#F0F9FF', border: '#BAE6FD', emoji: '🔬' },
  };

  const cards = domainEntries.map(([domainKey, brief]) => {
    const dm       = DOMAIN_META[domainKey] || DOMAIN_META.unknown;
    const summary  = safeStr(brief.domainSummary);
    const actions  = safeArr(brief.topActionItems);
    const watchList = safeArr(brief.watchList);
    const riskFlag  = safeStr(brief.riskFlag);
    const oppFlag   = safeStr(brief.opportunityFlag);

    // Action items rows
    const actionRows = actions.length > 0
      ? actions.map(a => `
          <tr>
            <td style="padding:8px 10px;font-size:13px;color:#374151;border-bottom:1px solid #F3F4F6;">${esc(a.action || a.text || a)}</td>
            <td style="padding:8px 10px;font-size:12px;border-bottom:1px solid #F3F4F6;white-space:nowrap;">
              <span style="background:${a.priority==='P1'?'#FEE2E2':a.priority==='P2'?'#FEF3C7':'#F3F4F6'};
                           color:${a.priority==='P1'?'#991B1B':a.priority==='P2'?'#92400E':'#374151'};
                           padding:2px 8px;border-radius:10px;font-weight:600;">${esc(a.priority||'P3')}</span>
            </td>
            <td style="padding:8px 10px;font-size:12px;color:#6B7280;border-bottom:1px solid #F3F4F6;">${esc(a.owner||'—')}</td>
            <td style="padding:8px 10px;font-size:12px;color:#6B7280;border-bottom:1px solid #F3F4F6;white-space:nowrap;">${esc(a.deadline||'—')}</td>
          </tr>`).join('')
      : `<tr><td colspan="4" style="padding:10px;color:#9CA3AF;font-size:13px;text-align:center;">No action items.</td></tr>`;

    // Watch list
    const watchItems = watchList.length > 0
      ? `<ul style="margin:8px 0 0 0;padding-left:20px;">
          ${watchList.map(w => `<li style="font-size:13px;color:#374151;margin-bottom:4px;line-height:1.5;">${esc(safeStr(w))}</li>`).join('')}
         </ul>`
      : '';

    return `
    <div style="border:1px solid ${dm.border};border-radius:8px;margin-bottom:20px;overflow:hidden;">
      <!-- Domain header -->
      <div style="background:${dm.bg};padding:14px 20px;border-bottom:1px solid ${dm.border};display:flex;justify-content:space-between;align-items:center;">
        <div>
          <span style="font-size:16px;margin-right:8px;">${dm.emoji}</span>
          <strong style="color:${dm.color};font-size:15px;">${dm.label} Intelligence</strong>
        </div>
        ${riskFlag ? `<span style="font-size:12px;color:#6B7280;">${esc(riskFlag)}</span>` : ''}
      </div>

      <div style="padding:16px 20px;">
        <!-- Summary -->
        ${summary ? `<p style="font-size:14px;color:#1F2937;line-height:1.7;margin:0 0 16px;">${esc(summary)}</p>` : ''}

        <!-- Opportunity flag -->
        ${oppFlag ? `<div style="background:#F0FDF4;border-left:3px solid #16A34A;padding:10px 14px;border-radius:0 6px 6px 0;margin-bottom:16px;font-size:13px;color:#166534;">
          <strong>💡 Opportunity:</strong> ${esc(oppFlag)}
        </div>` : ''}

        <!-- Action items table -->
        ${actions.length > 0 ? `
        <div style="margin-bottom:16px;">
          <div style="font-size:11px;font-weight:700;letter-spacing:1px;color:#6B7280;margin-bottom:8px;text-transform:uppercase;">Action Items</div>
          <table style="width:100%;border-collapse:collapse;border:1px solid #E5E7EB;border-radius:6px;overflow:hidden;">
            <thead>
              <tr style="background:#F9FAFB;">
                <th style="padding:8px 10px;text-align:left;font-size:11px;font-weight:600;color:#6B7280;text-transform:uppercase;border-bottom:2px solid #E5E7EB;">Action</th>
                <th style="padding:8px 10px;text-align:left;font-size:11px;font-weight:600;color:#6B7280;text-transform:uppercase;border-bottom:2px solid #E5E7EB;width:70px;">Priority</th>
                <th style="padding:8px 10px;text-align:left;font-size:11px;font-weight:600;color:#6B7280;text-transform:uppercase;border-bottom:2px solid #E5E7EB;width:160px;">Owner</th>
                <th style="padding:8px 10px;text-align:left;font-size:11px;font-weight:600;color:#6B7280;text-transform:uppercase;border-bottom:2px solid #E5E7EB;width:100px;">Deadline</th>
              </tr>
            </thead>
            <tbody>${actionRows}</tbody>
          </table>
        </div>` : ''}

        <!-- Watch list -->
        ${watchList.length > 0 ? `
        <div>
          <div style="font-size:11px;font-weight:700;letter-spacing:1px;color:#6B7280;margin-bottom:6px;text-transform:uppercase;">👁 Watch List</div>
          ${watchItems}
        </div>` : ''}
      </div>
    </div>`;
  });

  return `
  <h3 style="margin:0 0 16px;color:#1E293B;font-size:16px;border-bottom:2px solid #E5E7EB;padding-bottom:8px;">
    Domain Intelligence Briefings
  </h3>
  ${cards.join('')}`;
};

// ── §2E  Domain summary table (if analytics available) ───────────────────────
const buildDomainTable = () => {
  const rows = Object.entries(aDomains);
  if (rows.length === 0) return '';

  const domainRows = rows.map(([dom, v]) => {
    if (!v) return '';
    const trend = safeObj(safeObj(sharedAnalytics.trends).domainTrends)[dom] || {};
    const arrow = safeStr(trend.arrow, '→');
    const pct   = safeStr(trend.pct, '0');
    const high  = safeNum(v.high);
    return `<tr>
      <td style="padding:10px 12px;font-weight:600;color:#1E293B;text-transform:uppercase;font-size:12px;">${esc(dom)}</td>
      <td style="padding:10px 12px;text-align:center;">${safeNum(v.total)}</td>
      <td style="padding:10px 12px;text-align:center;">
        <span style="color:${high>0?'#DC2626':'#6B7280'};font-weight:${high>0?'700':'400'};">${high}</span>
      </td>
      <td style="padding:10px 12px;text-align:center;">${safeNum(v.competitor)}</td>
      <td style="padding:10px 12px;text-align:center;">${safeNum(v.urgent)}</td>
      <td style="padding:10px 12px;text-align:center;">${safeNum(v.avgScore,0).toFixed(1)}</td>
      <td style="padding:10px 12px;text-align:center;color:${pct>0?'#16A34A':pct<0?'#DC2626':'#6B7280'};">${arrow}${pct}%</td>
    </tr>`;
  }).join('');

  return `
  <h3 style="margin:0 0 12px;color:#1E293B;font-size:15px;">Domain Analytics Summary</h3>
  <table style="margin-bottom:24px;border:1px solid #E5E7EB;border-radius:6px;overflow:hidden;">
    <thead>
      <tr>
        <th>Domain</th><th style="text-align:center;">Total</th><th style="text-align:center;">HIGH</th>
        <th style="text-align:center;">Competitor</th><th style="text-align:center;">Urgent</th>
        <th style="text-align:center;">Avg Score</th><th style="text-align:center;">Trend</th>
      </tr>
    </thead>
    <tbody>${domainRows}</tbody>
  </table>`;
};

