// ═══════════════════════════════════════════════════════════════════════════════
// §0  HELPERS
// ═══════════════════════════════════════════════════════════════════════════════

const safeStr  = (v, fb = '')  => { if (v == null) return fb; const s = String(v).replace(/[\u0000-\u001F]/g, '').trim(); return s || fb; };
const safeNum  = (v, fb = 0)  => { const n = Number(v); return Number.isFinite(n) ? n : fb; };
const safeBool = (v)           => v === true || v === 'true' || v === 1 || v === '1';
const safeObj  = (v)           => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};
const safeArr  = (v)           => Array.isArray(v) ? v : [];
const isoNow   = ()            => new Date().toISOString();
const roundF   = (v, d = 2)   => { const n = safeNum(v, null); return n !== null ? +n.toFixed(d) : 0; };

/**
 * Escape a single CSV field value:
 *   - Wrap in double-quotes if contains comma, newline, double-quote, or leading/trailing space
 *   - Escape internal double-quotes by doubling them
 *   - Strip control characters that break CSV parsers
 */
const csvField = (v) => {
  if (v === null || v === undefined) return '';
  const s = String(v)
    .replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g, '') // strip bad control chars
    .replace(/\r\n/g, ' ')   // normalize CRLF to space
    .replace(/\r/g, ' ')     // normalize CR to space
    .replace(/\n/g, ' ');    // normalize LF to space (keep data on one CSV row)
  // Wrap in quotes if needed
  if (s.includes('"') || s.includes(',') || s.includes('\n') || s !== s.trim()) {
    return '"' + s.replace(/"/g, '""') + '"';
  }
  return s;
};

/**
 * Build one CSV row from an array of values.
 * Handles nulls, numbers, booleans, objects, arrays.
 */
const csvRow = (values) =>
  values.map(v => {
    if (v === null || v === undefined) return '';
    if (typeof v === 'boolean') return v ? 'TRUE' : 'FALSE';
    if (typeof v === 'number')  return String(v);
    if (Array.isArray(v))       return csvField(v.join(' | '));
    if (typeof v === 'object')  return csvField(JSON.stringify(v));
    return csvField(String(v));
  }).join(',');

/**
 * Build a complete CSV string from a header array and rows array-of-arrays.
 * Adds UTF-8 BOM for correct Excel/Google Sheets rendering.
 */
const buildCsv = (headers, rows) => {
  const bom        = '\uFEFF'; // UTF-8 BOM — required for Excel to open correctly
  const headerLine = headers.map(h => csvField(h)).join(',');
  const dataLines  = rows.map(r => csvRow(r));
  return bom + [headerLine, ...dataLines].join('\r\n');
};

/** Parse JSON string safely */
const parseJ = (v, fallback = {}) => {
  if (!v) return fallback;
  if (typeof v === 'object') return v;
  try { return JSON.parse(v); } catch (_) { return fallback; }
};

/** Format ISO date to readable string */
const fmtDate = (s) => {
  try {
    return s ? new Date(s).toLocaleDateString('en-US', { year:'numeric', month:'short', day:'2-digit' }) : '';
  } catch (_) { return safeStr(s); }
};

/** Format ISO timestamp */
const fmtTs = (s) => {
  try {
    return s ? new Date(s).toISOString().replace('T',' ').slice(0,19) + ' UTC' : '';
  } catch (_) { return safeStr(s); }
};

// ═══════════════════════════════════════════════════════════════════════════════
// §1  LOAD & AGGREGATE ALL INPUT ITEMS
// ═══════════════════════════════════════════════════════════════════════════════

const allItems = $input.all();
if (!allItems || allItems.length === 0) {
  throw new Error('[PharmaOS:CsvExport] No input items — check upstream node');
}

// Aggregate domain briefings across all items (one item per domain call)
const allDomainBriefings = {};  // { domainKey: briefingObj }
let   totalTokens        = 0;
let   totalPromptTokens  = 0;
let   totalCompTokens    = 0;
let   totalCost          = 0;
let   runId              = '';
let   today              = new Date().toISOString().slice(0, 10);
let   pipeVer            = '—';
let   modelUsed          = '';
let   sharedAnalytics    = {};
let   sharedMeta         = {};
let   execAIResult       = {};
const itemTokenRows      = []; // for csvTokenUsage

for (const [idx, item] of allItems.entries()) {
  const d = safeObj(item.json);

  // ── Domain briefings ───────────────────────────────────────────────────────
  const briefings = safeObj(d.domainBriefings);
  for (const [domainKey, briefObj] of Object.entries(briefings)) {
    if (briefObj && typeof briefObj === 'object') {
      allDomainBriefings[domainKey] = briefObj;
    }
  }

  // Fallback: parse choices[0].message.content if domainBriefings not pre-parsed
  if (Object.keys(briefings).length === 0) {
    const choices = safeArr(d.choices);
    if (choices.length > 0) {
      const content = safeStr(choices[0]?.message?.content);
      if (content) {
        const parsed    = parseJ(content, {});
        const domainKey = safeStr(d.domainBriefings?.unknown?._domain || `item_${idx}`);
        allDomainBriefings[domainKey] = { ...parsed, _domain: domainKey };
      }
    }
  }

  // ── Token aggregation ──────────────────────────────────────────────────────
  const usage        = safeObj(d.usage);
  const ptokens      = safeNum(usage.prompt_tokens);
  const ctokens      = safeNum(usage.completion_tokens);
  const ttokens      = safeNum(usage.total_tokens);
  const cost         = safeNum(usage.cost);
  const costDetails  = safeObj(usage.cost_details);

  totalTokens       += ttokens;
  totalPromptTokens += ptokens;
  totalCompTokens   += ctokens;
  totalCost         += cost;

  if (!modelUsed) modelUsed = safeStr(d.model);

  // Per-item token row
  itemTokenRows.push([
    idx + 1,
    safeStr(d.id),
    safeStr(d.model),
    safeStr(d.provider),
    ptokens,
    ctokens,
    ttokens,
    roundF(cost, 6),
    roundF(safeNum(costDetails.upstream_inference_prompt_cost), 6),
    roundF(safeNum(costDetails.upstream_inference_completions_cost), 6),
    safeNum(safeObj(usage.prompt_tokens_details).cached_tokens),
    safeNum(safeObj(usage.completion_tokens_details).reasoning_tokens),
    safeStr(d.choices?.[0]?.finish_reason),
    fmtTs(isoNow()),
  ]);

  // ── Shared context ─────────────────────────────────────────────────────────
  if (d.analytics)   sharedAnalytics = safeObj(d.analytics);
  if (d._meta)       sharedMeta      = safeObj(d._meta);
  if (d.today)       today           = safeStr(d.today);
  if (d.runId)       runId           = safeStr(d.runId);
  if (d.pipelineversion || sharedMeta.pipeline_version) {
    pipeVer = safeStr(d.pipelineversion || sharedMeta.pipeline_version);
  }
  if (d.execAI_result || d.execAIResult) {
    execAIResult = safeObj(d.execAI_result || d.execAIResult);
  }
}

// ── Analytics sub-objects ─────────────────────────────────────────────────────
const aGlobal    = safeObj(sharedAnalytics.global);
const aRisk      = safeObj(sharedAnalytics.risk);
const aCompounds = safeObj(sharedAnalytics.compounds);
const aPortfolio = safeObj(sharedAnalytics.portfolio);
const aDomains   = safeObj(sharedAnalytics.domains);
const aFlags     = safeObj(safeObj(sharedAnalytics.analytics).flags);
const aCompRad   = safeArr(sharedAnalytics.competitorRadar);
const aHeatmap   = safeArr(sharedAnalytics.indicationHeatmap);
const aStratMem  = safeArr(sharedAnalytics.strategyMemory);
const aCompEvts  = safeArr(sharedAnalytics.compoundEvents);
const aTopSigs   = safeArr(sharedAnalytics.topSignals);

const riskLevel  = safeStr(aRisk.level, 'UNKNOWN').toUpperCase();
const riskScore  = safeNum(aRisk.score, 0);
const builtAt    = safeStr(sharedMeta.built_at || isoNow());
const domainList = Object.keys(allDomainBriefings);

// ═══════════════════════════════════════════════════════════════════════════════
// §2  CSV 1 — DOMAIN BRIEFINGS MASTER (one row per domain)
// ═══════════════════════════════════════════════════════════════════════════════

const CSV_DOMAIN_HEADERS = [
  'RunID', 'ExportDate', 'PipelineVersion', 'Model',
  'Domain', 'Audience',
  'DomainSummary',
  'RiskFlag', 'OpportunityFlag',
  'ActionItemCount', 'WatchListCount',
  'TotalSignals', 'HighSignals', 'MedSignals', 'UrgentSignals',
  'CompetitorSignals', 'CriticalTier',
  'AvgImpactScore', 'PeakImpactScore',
  'OverallRiskLevel', 'OverallRiskScore',
  'SafetyEscalation', 'ImmediateAction', 'ExecutiveEscalations',
  'TotalTokens', 'TotalCostUSD',
  'BuiltAt',
];

const csvDomainRows = domainList.map(domainKey => {
  const b          = safeObj(allDomainBriefings[domainKey]);
  const actions    = safeArr(b.topActionItems);
  const watchList  = safeArr(b.watchList);
  const domSummary = safeStr(b.domainSummary);
  const riskFlag   = safeStr(b.riskFlag);
  const oppFlag    = safeStr(b.opportunityFlag);
  const audience   = safeStr(b._audience || b.audience);

  return [
    runId, today, pipeVer, modelUsed,
    domainKey, audience,
    domSummary,
    riskFlag, oppFlag,
    actions.length, watchList.length,
    safeNum(aGlobal.totalSignals),
    safeNum(aGlobal.highCount),
    safeNum(aGlobal.medCount),
    safeNum(aGlobal.urgentCount),
    safeNum(aGlobal.competitorCount),
    safeNum(aGlobal.criticalTierCount),
    roundF(aGlobal.avgImpact),
    roundF(aGlobal.peakImpact),
    riskLevel, riskScore,
    safeBool(aFlags.hasSafetyEscalation),
    safeBool(aFlags.requiresImmediateAction),
    safeNum(aCompounds.executiveEscalations),
    totalTokens,
    roundF(totalCost, 6),
    fmtTs(builtAt),
  ];
});

const csvDomainSummary = buildCsv(CSV_DOMAIN_HEADERS, csvDomainRows);

// ═══════════════════════════════════════════════════════════════════════════════
// §3  CSV 2 — ACTION ITEMS (one row per action item across all domains)
// ═══════════════════════════════════════════════════════════════════════════════

const CSV_ACTION_HEADERS = [
  'RunID', 'ExportDate', 'PipelineVersion',
  'Domain', 'ActionIndex',
  'Action', 'Priority', 'Owner', 'Deadline',
  'DeadlineParsed', 'DaysUntilDeadline',
  'DomainRiskFlag', 'DomainOpportunityFlag',
  'IsOverdue', 'BuiltAt',
];

const csvActionRows = [];
for (const domainKey of domainList) {
  const b       = safeObj(allDomainBriefings[domainKey]);
  const actions = safeArr(b.topActionItems);
  const riskF   = safeStr(b.riskFlag);
  const oppF    = safeStr(b.opportunityFlag);

  actions.forEach((a, idx) => {
    const actionText = safeStr(a.action || a.text || a);
    const priority   = safeStr(a.priority, 'P3');
    const owner      = safeStr(a.owner, '—');
    const deadline   = safeStr(a.deadline, '');
    const isOverdue  = deadline ? new Date(deadline) < new Date() : false;
    const daysUntil  = deadline
      ? Math.ceil((new Date(deadline) - new Date()) / (1000 * 60 * 60 * 24))
      : '';

    csvActionRows.push([
      runId, today, pipeVer,
      domainKey, idx + 1,
      actionText, priority, owner, deadline,
      fmtDate(deadline), daysUntil,
      riskF, oppF,
      isOverdue,
      fmtTs(builtAt),
    ]);
  });
}

const csvActionItems = buildCsv(CSV_ACTION_HEADERS, csvActionRows);

// ═══════════════════════════════════════════════════════════════════════════════
// §4  CSV 3 — WATCH LIST (one row per watch item across all domains)
// ═══════════════════════════════════════════════════════════════════════════════

const CSV_WATCH_HEADERS = [
  'RunID', 'ExportDate', 'PipelineVersion',
  'Domain', 'WatchIndex', 'WatchItem',
  'Category', 'DomainRiskFlag', 'BuiltAt',
];

const csvWatchRows = [];
for (const domainKey of domainList) {
  const b         = safeObj(allDomainBriefings[domainKey]);
  const watchList = safeArr(b.watchList);
  const riskF     = safeStr(b.riskFlag);

  watchList.forEach((w, idx) => {
    const watchText = safeStr(typeof w === 'object' ? (w.item || JSON.stringify(w)) : w);

    // Auto-categorise watch item by keyword
    const lower    = watchText.toLowerCase();
    const category = lower.includes('patent')       ? 'IP/Patent'
                   : lower.includes('partner')      ? 'Partnership'
                   : lower.includes('publication')  ? 'Publication'
                   : lower.includes('trial')        ? 'Clinical Trial'
                   : lower.includes('regulatory')   ? 'Regulatory'
                   : lower.includes('competitor')   ? 'Competitive'
                   : lower.includes('safety')       ? 'Safety'
                   : lower.includes('fda') || lower.includes('ema') ? 'Regulatory'
                   : lower.includes('acquisition') || lower.includes('deal') ? 'BD/M&A'
                   : 'General';

    csvWatchRows.push([
      runId, today, pipeVer,
      domainKey, idx + 1, watchText,
      category, riskF,
      fmtTs(builtAt),
    ]);
  });
}

const csvWatchList = buildCsv(CSV_WATCH_HEADERS, csvWatchRows);

// ═══════════════════════════════════════════════════════════════════════════════
// §5  CSV 4 — SIGNALS (from analytics.topSignals or domain topSignals)
// ═══════════════════════════════════════════════════════════════════════════════

const CSV_SIGNALS_HEADERS = [
  'RunID', 'ExportDate',
  'Domain', 'SignalType', 'Drug', 'Entity',
  'Indication', 'Sponsor', 'Phase', 'Geography',
  'ImpactLevel', 'ImpactScore', 'CompositeScore',
  'PriorityScore', 'QualityScore',
  'SafetySeverity', 'PatientImpact',
  'RecommendedAction', 'NotifPriority',
  'CompetitorFlag', 'IsUrgent',
  'Confidence', 'OverrideStatus',
  'MergeStatus', 'DuplicateRisk',
  'Stalenesstier', 'AgeHours',
  'SourceID', 'URL',
  'FirstSeenAt', 'LastSeenAt', 'IngestedAt',
  'AISummary', 'BuiltAt',
];

const csvSignalRows = [];

// Try top-level analytics signals first
for (const sig of aTopSigs) {
  if (!sig) continue;
  csvSignalRows.push([
    runId, today,
    safeStr(sig.signal_domain || sig.domain),
    safeStr(sig.signal_type   || sig.type),
    safeStr(sig.drug_name     || sig.drug),
    safeStr(sig.entity_name   || sig.entity),
    safeStr(sig.indication),
    safeStr(sig.sponsor),
    safeStr(sig.phase),
    safeStr(sig.geography),
    safeStr(sig.impact_level),
    safeNum(sig.impact_score),
    safeNum(sig.composite_score),
    safeNum(sig.priority_score),
    safeNum(sig.quality_score),
    safeStr(sig.safety_severity),
    safeStr(sig.patient_impact_estimate),
    safeStr(sig.recommended_action || sig.action),
    safeStr(sig.notif_priority),
    safeBool(sig.competitor_flag || sig.competitor),
    safeBool(sig.is_urgent       || sig.urgent),
    safeStr(sig.confidence),
    safeStr(sig.override_status),
    safeStr(sig.merge_status),
    safeStr(sig.duplicaterisk    || sig.duplicate_risk),
    safeStr(sig.staleness_tier),
    roundF(sig.age_hours),
    safeStr(sig.source_id || sig.signal_id || sig.id),
    safeStr(sig.url),
    fmtTs(sig.first_seen_at),
    fmtTs(sig.last_seen_at),
    fmtTs(sig.ingested_at),
    safeStr(sig.ai_summary    || sig.summary),
    fmtTs(builtAt),
  ]);
}

// Also pull from domain topSignals arrays
for (const domainKey of Object.keys(aDomains)) {
  const ds  = safeObj(aDomains[domainKey]);
  const top = safeArr(ds.topSignals);
  for (const sig of top) {
    if (!sig) continue;
    csvSignalRows.push([
      runId, today,
      safeStr(domainKey),
      safeStr(sig.signal_type || sig.type),
      safeStr(sig.drug_name   || sig.drug),
      safeStr(sig.entity_name || sig.entity),
      safeStr(sig.indication),
      safeStr(sig.sponsor),
      safeStr(sig.phase),
      safeStr(sig.geography),
      safeStr(sig.impact_level),
      safeNum(sig.impact_score),
      safeNum(sig.composite_score),
      safeNum(sig.priority_score),
      safeNum(sig.quality_score),
      safeStr(sig.safety_severity),
      safeStr(sig.patient_impact_estimate),
      safeStr(sig.recommended_action || sig.action),
      safeStr(sig.notif_priority),
      safeBool(sig.competitor_flag || sig.competitor),
      safeBool(sig.is_urgent       || sig.urgent),
      safeStr(sig.confidence),
      safeStr(sig.override_status),
      safeStr(sig.merge_status),
      safeStr(sig.duplicaterisk    || sig.duplicate_risk),
      safeStr(sig.staleness_tier),
      roundF(sig.age_hours),
      safeStr(sig.source_id || sig.signal_id || sig.id),
      safeStr(sig.url),
      fmtTs(sig.first_seen_at),
      fmtTs(sig.last_seen_at),
      fmtTs(sig.ingested_at),
      safeStr(sig.ai_summary    || sig.summary),
      fmtTs(builtAt),
    ]);
  }
}

const csvExport = buildCsv(CSV_SIGNALS_HEADERS, csvSignalRows);

