// ═══════════════════════════════════════════════════════════════════════════════
// §0  HELPERS — all defined before any usage
// ═══════════════════════════════════════════════════════════════════════════════

/** Safe string — null-safe, trim, control-char strip, fallback */
const safeStr = (v, fb = '') => {
  if (v === null || v === undefined) return fb;
  return String(v)
    .replace(/[\u0000-\u001F\u007F-\u009F]/g, '')
    .replace(/\s+/g, ' ')
    .trim() || fb;
};

/** Safe number — returns fb if not finite */
const safeNum = (v, fb = null) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : fb;
};

/** Safe boolean */
const safeBool = (v) => v === true || v === 'true' || v === 1 || v === '1';

/** Safe object — returns {} if not a plain object */
const safeObj = (v) => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};

/** Safe array — returns [] if not array */
const safeArr = (v) => Array.isArray(v) ? v : [];

/** Truncate string to max length */
const trunc = (s, mx) => {
  const str = safeStr(s);
  return str.length > mx ? str.slice(0, mx - 1) + '…' : str;
};

/** Round to N decimal places */
const roundF = (n, d = 1) => Number.isFinite(safeNum(n)) ? +safeNum(n).toFixed(d) : null;

/** ISO now */
const isoNow = () => new Date().toISOString();

/**
 * Clamp to PagerDuty's four valid severity levels.
 * PD Events API v2: critical > error > warning > info
 */
const clampSeverity = (v) => {
  const s = safeStr(v).toLowerCase();
  if (['critical', 'error', 'warning', 'info'].includes(s)) return s;
  return 'critical';
};

/**
 * Derive PagerDuty severity from PharmaOS signal fields.
 * Safety domain + CRITICAL/SERIOUS = critical
 * HIGH impact + urgent = critical
 * HIGH impact = error
 * MED = warning
 * else = info
 */
const deriveSeverity = (item, a) => {
  const domain      = safeStr(item.signal_domain || safeObj(a.global).domain);
  const impactLevel = safeStr(item.impact_level).toUpperCase();
  const safetySev   = safeStr(item.safety_severity).toUpperCase();
  const isUrgent    = safeBool(item.is_urgent);
  const riskScore   = safeNum(safeObj(a.risk).score, 0);
  const execEsc     = safeNum(safeObj(a.compounds).executiveEscalations, 0);
  const hasSafetyEsc = safeBool(safeObj(safeObj(a.analytics).flags).hasSafetyEscalation);

  // Explicit override wins first
  if (item.pagerdutySeverity) return clampSeverity(item.pagerdutySeverity);

  // Safety domain with high severity → always critical
  if (domain === 'safety' && ['CRITICAL', 'SERIOUS'].includes(safetySev)) return 'critical';

  // Executive escalation active → critical
  if (execEsc > 0 || hasSafetyEsc) return 'critical';

  // Risk score thresholds
  if (riskScore >= 80) return 'critical';
  if (riskScore >= 60) return 'error';

  // Impact level
  if (impactLevel === 'HIGH' && isUrgent) return 'critical';
  if (impactLevel === 'HIGH')             return 'error';
  if (impactLevel === 'MED')              return 'warning';

  return 'info';
};

/**
 * Derive PD event_action: trigger / resolve / acknowledge
 * Resolve if merge_status = RESOLVED or recommended_action = DISMISS
 * Acknowledge if recommended_action = MONITOR
 */
const deriveEventAction = (item) => {
  if (item.pagerdutyEventAction) {
    const a = safeStr(item.pagerdutyEventAction).toLowerCase();
    if (['trigger', 'resolve', 'acknowledge'].includes(a)) return a;
  }
  const mergeStatus = safeStr(item.merge_status).toUpperCase();
  const action      = safeStr(item.recommended_action).toUpperCase();
  if (mergeStatus === 'RESOLVED' || action === 'DISMISS') return 'resolve';
  if (action === 'MONITOR') return 'acknowledge';
  return 'trigger';
};

/**
 * Build a stable dedup key.
 * For the same incident (same signal + domain + day), the key must be
 * identical across retries so PD deduplicates correctly.
 * Format: pharmaos-{domain}-{signalId|runId}-{YYYY-MM-DD}
 */
const buildDedupKey = (item) => {
  if (item.pagerdutyDedupKey) {
    return trunc(`pharmaos-${safeStr(item.pagerdutyDedupKey)}`, 255);
  }

  const domain   = safeStr(item.signal_domain || 'wf4');
  const signalId = safeStr(
    item.source_id   ||
    item.signal_id   ||
    item.runId       ||
    item.id          ||
    $execution?.id   ||
    Date.now().toString()
  );

  // Date component makes key daily-stable (same incident same day = same key)
  const dateStamp = new Date().toISOString().slice(0, 10); // YYYY-MM-DD

  return trunc(`pharmaos-${domain}-${signalId}-${dateStamp}`, 255);
};

