/** Safely coerce to finite number, return fb if not finite */
const numOr  = (v, fb = 0)   => { const n = Number(v); return Number.isFinite(n) ? n : fb; };

/** Safe string: null-safe, trim, control-char strip, fallback */
const safe   = (v, fb = 'N/A') => {
  if (v === null || v === undefined) return fb;
  const s = String(v).replace(/[\u0000-\u001F\u007F-\u009F]/g, '').replace(/\s+/g, ' ').trim();
  return s || fb;
};

/** Truncate with ellipsis */
const trunc  = (s, mx)        => { const str = safe(s, ''); return str.length > mx ? str.slice(0, mx) + '…[truncated]' : str; };

/** Clamp number */
const clamp  = (n, lo, hi)    => Math.max(lo, Math.min(hi, n));

/** Round to N decimal places */
const roundF = (n, d = 1)     => Number.isFinite(numOr(n)) ? +numOr(n).toFixed(d) : 'N/A';

/** Safe array access — returns [] if not array */
const safeArr = (v)            => Array.isArray(v) ? v : [];

/** Safe object access — returns {} if not object */
const safeObj = (v)            => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};

/** Format minutes → human label */
const fmtMin  = (m)            => {
  const n = numOr(m, 0);
  if (n < 60)    return `${Math.round(n)}min`;
  if (n < 1440)  return `${roundF(n / 60, 1)}h`;
  return `${roundF(n / 1440, 1)}d`;
};

/** ISO now */
const isoNow  = ()             => new Date().toISOString();

