const safeStr  = (v, fb = '')  => { if (v == null) return fb; const s = String(v).replace(/[\u0000-\u001F]/g,'').trim(); return s || fb; };
const safeNum  = (v, fb = 0)  => { const n = Number(v); return Number.isFinite(n) ? n : fb; };
const safeBool = (v)           => v === true || v === 'true' || v === 1;
const safeObj  = (v)           => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};
const safeArr  = (v)           => Array.isArray(v) ? v : [];
const isoNow   = ()            => new Date().toISOString();

/** Truncate to Slack text limit */
const slk = (v, max = 3000) => {
  const s = safeStr(v);
  return s.length > max ? s.slice(0, max - 1) + '…' : s;
};

/** Priority badge */
const prioBadge = (p) => {
  const s = safeStr(p).toUpperCase();
  return s === 'P1' ? '🔴 P1' : s === 'P2' ? '🟠 P2' : s === 'P3' ? '🟡 P3' : `• ${s || '—'}`;
};

/** Section text block */
const txt = (text) => ({ type: 'section', text: { type: 'mrkdwn', text: slk(text) } });

/** Header block */
const hdr = (text) => ({
  type: 'header',
  text: { type: 'plain_text', text: slk(text, 150), emoji: true },
});

/** Context footer */
const ctx = (...parts) => ({
  type: 'context',
  elements: [{ type: 'mrkdwn', text: slk(parts.filter(Boolean).join(' | '), 2000) }],
});

/** Divider */
const DIV = { type: 'divider' };

/** Add block with 50-block cap guard */
const add = (arr, ...blocks) => {
  for (const b of blocks) {
    if (!b) continue;
    if (arr.length >= 49) {
      arr.push(ctx('⚠️ Additional content truncated — view full digest in dashboard'));
      break;
    }
    arr.push(b);
  }
};

// ═══════════════════════════════════════════════════════════════════════════════
// §1  LOAD INPUT
// ═══════════════════════════════════════════════════════════════════════════════

const item = $json;
if (!item || typeof item !== 'object') {
  throw new Error('[PharmaOS:SlackDomain] $json is null — check upstream node');
}

// ── Resolve domain key ────────────────────────────────────────────────────────
// Priority: currentDomain (set by router) → first key in domainBriefings → 'unknown'
const domainBriefings = safeObj(item.domainBriefings);
const domainKey = safeStr(
  item.currentDomain ||
  Object.keys(domainBriefings)[0] ||
  'unknown'
);

const briefing = safeObj(domainBriefings[domainKey] || domainBriefings.unknown || {});

// ── Domain display config ─────────────────────────────────────────────────────
const DOMAIN_META = {
  safety:     { emoji: '🛡️',  label: 'Safety Intelligence',         channel: '#pharmaos-safety'         },
  ci:         { emoji: '🔬',  label: 'Competitive Intelligence',     channel: '#pharmaos-ci-team'        },
  regulatory: { emoji: '📋',  label: 'Regulatory Intelligence',      channel: '#pharmaos-medical-affairs'},
  bd:         { emoji: '🤝',  label: 'Business Development',         channel: '#pharmaos-bd-team'        },
  unknown:    { emoji: '🧬',  label: 'Neuroscience / Academic Intel',channel: '#pharmaos-intelligence'   },
  general:    { emoji: '🧬',  label: 'General Intelligence',         channel: '#pharmaos-intelligence'   },
};

const dm      = DOMAIN_META[domainKey] || DOMAIN_META.unknown;
const emoji   = safeStr(dm.emoji, '📊');
const label   = safeStr(briefing._label || dm.label);
const channel = safeStr(item.slackChannel || dm.channel, '#pharmaos-ops');

// ── Briefing fields ───────────────────────────────────────────────────────────
const domainSummary  = safeStr(briefing.domainSummary);
const keyInsight     = safeStr(briefing.keyInsight);
const riskFlag       = safeStr(briefing.riskFlag,       'No elevated risk.');
const oppFlag        = safeStr(briefing.opportunityFlag,'None highlighted.');
const actions        = safeArr(briefing.topActionItems);
const watchList      = safeArr(briefing.watchList);
const needsEsc       = safeBool(briefing.escalationNeeded);
const audience       = safeStr(briefing._audience || briefing.audience);

// ── Analytics for this domain (if available) ──────────────────────────────────
const ds = safeObj(safeObj(safeObj(item.analytics).domains)[domainKey]);
const total      = safeNum(ds.total);
const high       = safeNum(ds.high);
const med        = safeNum(ds.med);
const competitor = safeNum(ds.competitor);
const urgent     = safeNum(ds.urgent);
const avgScore   = safeNum(ds.avgScore, 0).toFixed(1);
const topSigs    = safeArr(ds.topSignals);

// ── Meta ──────────────────────────────────────────────────────────────────────
const today   = safeStr(item.today || new Date().toISOString().slice(0, 10));
const runId   = safeStr(item.runId || safeObj(item._meta).run_id, '—');
const model   = safeStr(item.model || safeObj(safeArr(item.choices)[0]).model || safeObj(item._meta).model);
const usage   = safeObj(item.usage);
const tokens  = safeNum(usage.total_tokens);
const cost    = safeNum(usage.cost, 0);

// ═══════════════════════════════════════════════════════════════════════════════
// §2  BUILD BLOCKS
// ═══════════════════════════════════════════════════════════════════════════════

const blocks = [];

// ── HEADER ────────────────────────────────────────────────────────────────────
add(blocks,
  hdr(`${emoji} ${label} — ${today}`)
);

// ── ESCALATION BANNER ─────────────────────────────────────────────────────────
if (needsEsc) {
  add(blocks,
    txt(':rotating_light: *ESCALATION REQUIRED* — Domain lead must review immediately.')
  );
}

// ── AUDIENCE TAG ──────────────────────────────────────────────────────────────
if (audience) {
  add(blocks,
    txt(`_Audience: ${slk(audience, 200)}_`)
  );
}

// ── SIGNAL METRICS (if analytics available) ───────────────────────────────────
if (total > 0) {
  add(blocks,
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Total Signals*\n${total}` },
        { type: 'mrkdwn', text: `*HIGH*\n${high > 0 ? `🔴 ${high}` : high}` },
        { type: 'mrkdwn', text: `*MED*\n${med}` },
        { type: 'mrkdwn', text: `*Competitor*\n${competitor > 0 ? `⚔️ ${competitor}` : competitor}` },
        { type: 'mrkdwn', text: `*Urgent*\n${urgent > 0 ? `🚨 ${urgent}` : urgent}` },
        { type: 'mrkdwn', text: `*Avg Score*\n${avgScore}` },
      ],
    },
    DIV
  );
}

// ── RISK / OPPORTUNITY ────────────────────────────────────────────────────────
const showRisk = riskFlag && !riskFlag.toLowerCase().includes('no elevated');
const showOpp  = oppFlag  && !oppFlag.toLowerCase().includes('none highlighted');

if (showRisk || showOpp) {
  const riskFields = [];
  if (showRisk) riskFields.push({ type: 'mrkdwn', text: slk(`*⚠️ Risk Flag*\n${riskFlag}`, 300) });
  if (showOpp)  riskFields.push({ type: 'mrkdwn', text: slk(`*💡 Opportunity*\n${oppFlag}`, 300) });
  // Always show both fields even if one is default — keeps layout consistent
  if (!showRisk) riskFields.unshift({ type: 'mrkdwn', text: `*⚠️ Risk Flag*\n${riskFlag}` });
  if (!showOpp)  riskFields.push   ({ type: 'mrkdwn', text: `*💡 Opportunity*\n${oppFlag}` });

  add(blocks, { type: 'section', fields: riskFields.slice(0, 2) });
  add(blocks, DIV);
}

// ── KEY INSIGHT ───────────────────────────────────────────────────────────────
if (keyInsight) {
  add(blocks, txt(`*💡 Key Insight*\n${keyInsight}`), DIV);
}

// ── DOMAIN SUMMARY ────────────────────────────────────────────────────────────
if (domainSummary) {
  add(blocks, txt(`*Summary*\n${domainSummary}`));
  if (actions.length > 0 || watchList.length > 0) add(blocks, DIV);
}

// ── ACTION ITEMS ──────────────────────────────────────────────────────────────
if (actions.length > 0) {
  const lines = actions.slice(0, 5).map((a, i) => {
    const action   = safeStr(a.action || a.text || a);
    const prio     = prioBadge(a.priority);
    const owner    = safeStr(a.owner, '—');
    const deadline = safeStr(a.deadline, '—');
    return `${i + 1}. ${prio} ${slk(action, 200)}\n    _Owner: *${owner}* · Due: \`${deadline}\`_`;
  });

  add(blocks,
    txt(`*📋 Action Items (${actions.length}):*\n${lines.join('\n')}`),
    DIV
  );
}

// ── TOP SIGNALS (if analytics available) ──────────────────────────────────────
if (topSigs.length > 0) {
  add(blocks, txt(`*📡 Top Signals (${Math.min(topSigs.length, 3)} of ${topSigs.length}):*`));

  for (const [idx, s] of topSigs.slice(0, 3).entries()) {
    if (!s) continue;
    const drug     = safeStr(s.drug_name || s.drug || s.entity_name, 'Unknown');
    const impLvl   = safeStr(s.impact_level, 'MED').toUpperCase();
    const icon     = impLvl === 'HIGH' ? '🔴' : impLvl === 'MED' ? '🟡' : '🟢';
    const score    = safeNum(s.impact_score, 0);
    const sigType  = safeStr(s.signal_type, '—');
    const summary  = safeStr(s.ai_summary || s.summary, '').slice(0, 200);
    const url      = safeStr(s.url, '');
    const sigId    = safeStr(s.source_id || s.id || idx);
    const compFlag = safeBool(s.competitor_flag || s.competitor);
    const isUrgent = safeBool(s.is_urgent || s.urgent);

    const sigText = [
      `${icon} *${slk(drug, 80)}* | ${sigType} | Score: *${score}/10*`,
      compFlag ? '⚔️ Competitor' : null,
      isUrgent ? '🚨 Urgent'     : null,
      summary  ? `> ${summary}`  : null,
    ].filter(Boolean).join(' · ').replace(' · > ', '\n> ');

    const sigBlock = {
      type: 'section',
      text: { type: 'mrkdwn', text: slk(sigText) },
    };

    if (url) {
      sigBlock.accessory = {
        type: 'button',
        text: { type: 'plain_text', text: 'Source ↗', emoji: false },
        url:  url.slice(0, 3000),
        action_id: `sig_${safeStr(domainKey).slice(0,6)}_${safeStr(sigId).replace(/[^a-z0-9_-]/gi,'').slice(0,20)}_${idx}`,
      };
    }

    add(blocks, sigBlock);
  }

  add(blocks, DIV);
}

// ── WATCH LIST ────────────────────────────────────────────────────────────────
if (watchList.length > 0) {
  const lines = watchList.slice(0, 6).map((w, i) => {
    // Handle both string items and object items { item: '...' }
    const text = safeStr(typeof w === 'object' ? (w.item || w.text || JSON.stringify(w)) : w);
    return `${i + 1}. ${slk(text, 200)}`;
  });

  add(blocks,
    txt(`*👁 Watch List (next 48h):*\n${lines.join('\n')}`),
    DIV
  );
}

// ── CONTEXT FOOTER ────────────────────────────────────────────────────────────
add(blocks,
  ctx(
    `PharmaOS ${label}`,
    today,
    total > 0 ? `${total} signals` : null,
    tokens > 0 ? `${tokens.toLocaleString()} tokens ($${cost.toFixed(4)})` : null,
    model     ? model.replace('openai/','') : null,
    `Run: ${runId}`,
  )
);

// ═══════════════════════════════════════════════════════════════════════════════
// §3  NOTIFICATION TEXT (Slack mobile push fallback — plain text, no markdown)
// ═══════════════════════════════════════════════════════════════════════════════

const notificationParts = [
  `PharmaOS ${label} - ${today}`,
  total > 0 ? `${total} signals (${high} HIGH)` : null,
  showRisk ? `Risk: ${riskFlag.slice(0, 80)}` : null,
  actions.length > 0 ? `${actions.length} action item(s) require attention` : null,
].filter(Boolean);

const notificationText = notificationParts.join(' | ');

// ═══════════════════════════════════════════════════════════════════════════════
// §4  RETURN
// ═══════════════════════════════════════════════════════════════════════════════

return [{
  json: {
    // Slack Send Message node fields
    channel:          channel,
    text:             notificationText,    // mobile fallback
    blocks:           blocks.slice(0, 50), // Slack API hard limit
    notificationText,                      // backward compat alias

    // Routing context
    currentDomain:      domainKey,
    currentDomainLabel: label,
    blockCount:         Math.min(blocks.length, 50),

    // Pass through for downstream nodes
    domainBriefings:    item.domainBriefings,
    analytics:          item.analytics,
    today,
    runId,

    // Audit
    _slack_block_meta: {
      node:         'domain_slack_block_builder_single',
      version:      'v2.0.0',
      built_at:     isoNow(),
      domain_key:   domainKey,
      domain_label: label,
      channel,
      block_count:  Math.min(blocks.length, 50),
      action_items: actions.length,
      watch_items:  watchList.length,
      top_signals:  Math.min(topSigs.length, 3),
      tokens,
      cost_usd:     +cost.toFixed(6),
    },
  },
}];

// PharmaOS Ops Slack normalizer
const item = $json;

function safeString(v, fallback = '') {
  if (v === null || v === undefined) return fallback;
  if (typeof v === 'string') return v;
  try {
    return String(v);
  } catch {
    return fallback;
  }
}

function truncate(str, max = 300) {
  str = safeString(str, '');
  if (str.length <= max) return str;
  return str.slice(0, max - 1) + '…';
}

function isSlackBlock(b) {
  return b && typeof b === 'object' && typeof b.type === 'string';
}

// 1) Normalize opsSlackBlocks
let rawBlocks = item.opsSlackBlocks;

// Coerce single object → array
if (rawBlocks && !Array.isArray(rawBlocks) && typeof rawBlocks === 'object') {
  rawBlocks = [rawBlocks];
}

// Ensure array
if (!Array.isArray(rawBlocks)) {
  rawBlocks = [];
}

// Filter only valid‑looking blocks
const opsSlackBlocks = rawBlocks.filter(isSlackBlock);

// 2) Fallback header if blocks empty or header missing
const runId = safeString(item.runId || item.executionId || '');
const pipelineVersion = safeString(item.pipelineVersion || '');
const trigger = safeString(item.trigger || 'DAILY');

const headerTextBase = '⚙️ PharmaOS Ops Summary';
const headerTextSuffix =
  trigger || runId ? ` — ${[trigger, runId].filter(Boolean).join(' · ')}` : '';
const headerText = truncate(headerTextBase + headerTextSuffix, 150);

const hasHeader = opsSlackBlocks.some(b => b.type === 'header');

if (!hasHeader) {
  opsSlackBlocks.unshift({
    type: 'header',
    text: {
      type: 'plain_text',
      text: headerText,
      emoji: true,
    },
  });
}

// 3) Optional context footer enrichment
const completedAt = safeString(item.completedAt || item.completed_at || '');
const blindSpots = safeString(item.blindSpots ?? item.blind_spots ?? '0');
const compoundEvents = safeString(item.compoundEvents ?? item.compound_events ?? '0');

const contextLineParts = [];
if (completedAt) contextLineParts.push(`Completed: ${completedAt}`);
if (pipelineVersion) contextLineParts.push(`Pipeline v${pipelineVersion}`);
contextLineParts.push(`Blind Spots: ${blindSpots}`);
contextLineParts.push(`Compound Events: ${compoundEvents}`);

const contextText = truncate(contextLineParts.join(' | '), 300);

// Append context only if not already present
const hasContext = opsSlackBlocks.some(b => b.type === 'context');

if (!hasContext && contextText) {
  opsSlackBlocks.push({
    type: 'context',
    elements: [
      {
        type: 'mrkdwn',
        text: contextText,
      },
    ],
  });
}

// 4) Robust notification text
const baseSubject = safeString(item.emailSubject || '[PharmaOS 🟡] MODERATE — Intelligence Digest', '');
const notificationText = truncate(baseSubject.replace(/\s+/g, ' ').trim(), 250);

// 5) Return normalized item, preserving original fields
return [
  {
    json: {
      ...item,
      opsSlackBlocks,
      opsSlackNotificationText: notificationText,
    },
  },
];

