// ═══════════════════════════════════════════════════════════════════════════════
// §0  HELPERS
// ═══════════════════════════════════════════════════════════════════════════════

const safeStr = (v, fb = '') => {
  if (v === null || v === undefined) return fb;
  return String(v).trim() || fb;
};

const safeNum = (v, fb = 0) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : fb;
};

const safeObj = (v) => (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};

/**
 * Sanitize a filename:
 *   - Strip path separators and shell-unsafe chars
 *   - Collapse whitespace to hyphens
 *   - Strip leading dots and hyphens
 *   - Enforce .csv extension
 *   - Hard-cap at 120 characters
 */
const sanitizeFilename = (name, fallback = 'pharmaos-export.csv') => {
  let n = safeStr(name, '').toLowerCase();
  if (!n) n = fallback;

  n = n
    .replace(/[\/\\?%*:|"<>\u0000-\u001F]/g, '')  // strip unsafe chars
    .replace(/\s+/g, '-')                           // spaces → hyphens
    .replace(/-{2,}/g, '-')                         // collapse multiple hyphens
    .replace(/^[-\.]+/, '')                         // strip leading dots/hyphens
    .replace(/\.csv$/i, '')                         // remove existing .csv before re-adding
    .replace(/\.+$/, '');                           // strip trailing dots

  if (!n) n = fallback.replace(/\.csv$/i, '');

  // Hard cap — reserve 4 chars for .csv
  if (n.length > 116) n = n.slice(0, 116);

  return `${n}.csv`;
};

/**
 * Encode a CSV string to base64 binary.
 * Returns { data, fileName, mimeType, fileSize, fileExtension }
 */
const encodeCsv = (csvString, filename) => {
  // Ensure UTF-8 BOM is present (needed for Excel)
  const withBom   = csvString.startsWith('\uFEFF') ? csvString : '\uFEFF' + csvString;
  const buffer    = Buffer.from(withBom, 'utf-8');
  return {
    data:          buffer.toString('base64'),
    fileName:      filename,
    mimeType:      'text/csv; charset=utf-8',
    fileSize:      buffer.length,
    fileExtension: 'csv',
  };
};

/**
 * Validate CSV content — check it has at least a header row and is non-trivial.
 * Returns { valid, rowCount, colCount, warning }
 */
const validateCsv = (csvString, label) => {
  if (!csvString || typeof csvString !== 'string') {
    return { valid: false, rowCount: 0, colCount: 0, warning: `${label}: content is null or not a string` };
  }
  // Strip BOM for analysis
  const clean = csvString.replace(/^\uFEFF/, '').trim();
  if (!clean) {
    return { valid: false, rowCount: 0, colCount: 0, warning: `${label}: content is empty string` };
  }
  const lines    = clean.split(/\r?\n/).filter(l => l.trim());
  const rowCount = Math.max(0, lines.length - 1); // exclude header
  const colCount = lines[0] ? lines[0].split(',').length : 0;

  if (lines.length < 1) {
    return { valid: false, rowCount: 0, colCount: 0, warning: `${label}: no header row found` };
  }
  return { valid: true, rowCount, colCount, warning: null };
};

/** Format bytes to human-readable size */
const fmtBytes = (n) => {
  if (n < 1024)       return `${n} B`;
  if (n < 1048576)    return `${(n/1024).toFixed(1)} KB`;
  return `${(n/1048576).toFixed(2)} MB`;
};

const isoNow = () => new Date().toISOString();

