// ═══════════════════════════════════════════════════════════════════════════════
// §3  ENCODE ALL CSVs INTO BINARIES
// ═══════════════════════════════════════════════════════════════════════════════

const binaryOutput    = {};   // goes into item.binary
const fileManifest    = [];   // audit log of what was encoded
const validationLog   = [];   // any warnings
let   totalExportBytes = 0;
let   totalDataRows    = 0;

for (const def of CSV_DEFINITIONS) {
  const rawCsv    = safeStr(item[def.field], '');
  const csvString = rawCsv.trim() ? rawCsv : def.fallback;
  const isEmpty   = !rawCsv.trim();
  const filename  = sanitizeFilename(def.stem);

  // Validate
  const validation = validateCsv(csvString, def.label);
  if (validation.warning) {
    validationLog.push(validation.warning);
  }

  // Encode
  const encoded = encodeCsv(csvString, filename);

  // Register binary
  binaryOutput[def.field] = encoded;

  // Manifest entry
  const entry = {
    field:     def.field,
    label:     def.label,
    filename,
    fileSize:  fmtBytes(encoded.fileSize),
    fileSizeB: encoded.fileSize,
    rowCount:  validation.rowCount,
    colCount:  validation.colCount,
    isEmpty,
    valid:     validation.valid,
    warning:   validation.warning,
  };
  fileManifest.push(entry);

  totalExportBytes += encoded.fileSize;
  totalDataRows    += validation.rowCount;
}

// ═══════════════════════════════════════════════════════════════════════════════
// §4  PRIMARY BINARY — csvExportFile (backward-compat with downstream nodes)
// ═══════════════════════════════════════════════════════════════════════════════
// Keep the original field name so any existing Gmail / Google Drive nodes
// that reference 'csvExportFile' continue to work unchanged.

const primaryCsv     = safeStr(item.csvExport || item.csvContent, '');
const primaryContent = primaryCsv.trim()
  ? primaryCsv
  : 'RunID,ExportDate,Domain,SignalType,Drug,Indication,ImpactLevel,ImpactScore\r\n(no signal data available)';

const primaryFilename = sanitizeFilename(
  item.csvFilename ||
  `pharmaos-signals-${domainKey}-${fileDate}`,
  'pharmaos-signals-all.csv'
);

const primaryEncoded = encodeCsv(primaryContent, primaryFilename);
binaryOutput['csvExportFile'] = primaryEncoded;  // backward-compat alias

// Expose for downstream use (backward-compat with original node)
const csvFilename = primaryFilename;

// ═══════════════════════════════════════════════════════════════════════════════
// §5  BINARY EXPORT META
// ═══════════════════════════════════════════════════════════════════════════════

const binaryMeta = {
  node:              'csv_binary_export_builder',
  version:           'v2.0.0',
  built_at:          isoNow(),
  run_id:            runId,
  export_date:       today,
  pipeline_version:  pipeVer,
  files_encoded:     fileManifest.length + 1,  // +1 for primary alias
  total_bytes:       totalExportBytes + primaryEncoded.fileSize,
  total_bytes_human: fmtBytes(totalExportBytes + primaryEncoded.fileSize),
  total_data_rows:   totalDataRows,
  empty_files:       fileManifest.filter(f => f.isEmpty).length,
  validation_warnings: validationLog.length,
  files:             fileManifest,
  warnings:          validationLog,
  primary_file:      primaryFilename,
};

// ═══════════════════════════════════════════════════════════════════════════════
// §6  RETURN
// ═══════════════════════════════════════════════════════════════════════════════

return [{
  json: {
    ...item,

    // Filenames for downstream Gmail/Drive/Slack nodes
    csvFilename,                    // primary backward-compat filename
    csvFilenameSignals:             sanitizeFilename(`pharmaos-signals-${domainKey}-${fileDate}`),
    csvFilenameActionItems:         sanitizeFilename(`pharmaos-action-items-${fileDate}`),
    csvFilenameWatchList:           sanitizeFilename(`pharmaos-watch-list-${fileDate}`),
    csvFilenameDomainSummary:       sanitizeFilename(`pharmaos-domain-summary-${fileDate}`),
    csvFilenameExecutiveBrief:      sanitizeFilename(`pharmaos-executive-brief-${fileDate}`),
    csvFilenameTokenUsage:          sanitizeFilename(`pharmaos-token-usage-${fileDate}`),
    csvFilenameCompetitorRadar:     sanitizeFilename(`pharmaos-competitor-radar-${fileDate}`),
    csvFilenameIndicationHeatmap:   sanitizeFilename(`pharmaos-indication-heatmap-${fileDate}`),
    csvFilenameCompoundEvents:      sanitizeFilename(`pharmaos-compound-events-${fileDate}`),
    csvFilenameStrategyMemory:      sanitizeFilename(`pharmaos-strategy-memory-${fileDate}`),

    // Size/byte stats for logging
    csvBytes:           primaryEncoded.fileSize,
    csvBytesHuman:      fmtBytes(primaryEncoded.fileSize),
    csvTotalExportBytes: totalExportBytes,
    csvTotalBytesHuman:  fmtBytes(totalExportBytes),
    csvTotalDataRows:    totalDataRows,

    // Audit
    binaryMeta,
  },

  binary: binaryOutput,
}];
